-- Poems batch 372
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5da95255-0783-41dc-bf86-43a1ffd41b5c','再賦五至堂二首  其二','孫覿','宋','宋诗','song-poetry','','[]','老衲僧中龍，得度佛三世。',72,'全唐诗/poet.song.85000.json','["老衲僧中龍，得度佛三世。", "苴茅製不借，剖竹作如意。", "徴心訊空王，禮足依梵帝。", "住世無三宿，應緣有五至。", "百年杞國憂，四大偃師戲。", "應作如是觀，浮雲本無蒂。"]'),
('dd095e37-c2bc-497d-b127-0ff3f35eb6bd','胡恭夫勉齋','孫覿','宋','宋诗','song-poetry','','[]','爲山在進簣，學海自盈科。',96,'全唐诗/poet.song.85000.json','["爲山在進簣，學海自盈科。", "但見拳石小，纔容一葦過。", "駸駸拔地起，千丈青坡陀。", "漫漫拍天流，萬頃翠錯磨。", "勉齋何爲者，直意慕山河。", "高視俯遺垤，孤清鎮頹波。", "巨植蟠杞梓，修麟窘蛟鼉。", "誰能探高深，潛珍有隨和。"]'),
('e43d6ce8-8b95-4e26-b460-ac237998fa75','静節軒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','紅紫紛紛半在亡，一軒風雨送春忙。',32,'全唐诗/poet.song.85000.json','["紅紫紛紛半在亡，一軒風雨送春忙。", "青梅著子渾無數，綠笋穿林已許長。"]'),
('27ac0b0f-375e-46e8-8216-4851e77ca3df','静節軒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','蓮葉平鋪塘水滿，棟花半落渚風清。',32,'全唐诗/poet.song.85000.json','["蓮葉平鋪塘水滿，棟花半落渚風清。", "無言獨立蒼茫裏，更聽黄鸝一兩聲。"]'),
('cb741666-d500-440e-9207-536907aa7390','滁守平遠堂','孫覿','宋','宋诗','song-poetry','','[]','魏公大雅士，英英峙冰玉。',120,'全唐诗/poet.song.85000.json','["魏公大雅士，英英峙冰玉。", "平反廷尉府，共理滁陽牧。", "奮髯懾狐鼠，折箠行鳧鶩。", "高眠日照廊，坐嘯風生竹。", "度堂雲雨上，斗柄高插屋。", "擺落區中緣，超搖塵外躅。", "遙蒼擁鬟髻，漱碧韻琴筑。", "雖無花解笑，自有雲樹宿。", "王春亦已班，臣晝可屢卜。", "舉目送歸鴻，寄此千里目。"]'),
('54e2f0a7-71c1-4a0e-8f90-e98dfcd1ae9b','龜潭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','繞舍蒔蘭蓀，褰簾對竹君。',48,'全唐诗/poet.song.85000.json','["繞舍蒔蘭蓀，褰簾對竹君。", "移床栖樾蔭，脫屣護苔紋。", "釣影垂潭月，樵歌出嶺雲。", "殷勤一瓢水，侑此井中芹。"]'),
('437c02c2-73cc-486b-9422-26b36eb64ff4','龜潭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','風漣細娟娟，月彩光瀰瀰。',48,'全唐诗/poet.song.85000.json','["風漣細娟娟，月彩光瀰瀰。", "庭空韻琴筑，故入幽人耳。", "皓白有真色，澹泊非世味。", "誰能聽蛙淫，喚汝作鼓吹。"]'),
('9d24457b-6ea2-4f04-ae7d-2962d3331124','雨中泊蜀山見漁人自山半負樵入舟鼓棹而去','孫覿','宋','宋诗','song-poetry','','[]','一嶂横青靄，千漚起碧潯。',48,'全唐诗/poet.song.85000.json','["一嶂横青靄，千漚起碧潯。", "行穿山半腹，坐占水中心。", "蹋雨松蹊滑，衝煙蓼嶼深。", "時來有登涉，應不繫升沉。"]'),
('d59b9f27-4e54-41ce-a34d-5a55be818fc9','胡橋別墅','孫覿','宋','宋诗','song-poetry','','[]','覆地紅深寸，連村翠著行。',48,'全唐诗/poet.song.85000.json','["覆地紅深寸，連村翠著行。", "桑空蠶箔滿，芹老燕泥香。", "且泥無何飲，徐思有底忙。", "獨謠無語悟，倚杖立斜陽。"]'),
('3d6c7faa-1de9-4a37-94b3-fc8342ce36cf','示龜潭文上人二首  其一','孫覿','宋','宋诗','song-poetry','','[]','露蓋青相倚，雲屏翠作圍。',48,'全唐诗/poet.song.85000.json','["露蓋青相倚，雲屏翠作圍。", "石泉鳴牛枕，逕蘇上春衣。", "井遂登晨汲，庖煙起夕霏。", "浮生眠食耳，終不羨輕肥。"]'),
('6e841e75-82d9-4851-8411-5c4fc2c6ae11','示龜潭文上人二首  其二','孫覿','宋','宋诗','song-poetry','','[]','掃石風生坐，披雲雨濕衣。',48,'全唐诗/poet.song.85000.json','["掃石風生坐，披雲雨濕衣。", "飄飄一蟬脱，獵獵兩鳧飛。", "伏檻觀魚樂，鈎簾待燕歸。", "疏鍾何處寺，出谷自依依。"]'),
('bdf088d8-1065-4aa0-a497-fb742cb52dd7','讀類說二首  其一','孫覿','宋','宋诗','song-poetry','','[]','亡是談烏有，彭郎得小姑。',48,'全唐诗/poet.song.85000.json','["亡是談烏有，彭郎得小姑。", "誰言鳩作婦，謾道雁爲奴。", "絡緯那能織，提壺豈解酤。", "龜兹堪一笑，非馬亦非驢。"]'),
('75b8e23a-4d25-4308-af83-9b048a7c539a','讀類說二首  其二','孫覿','宋','宋诗','song-poetry','','[]','額痒會出耳，足閑仍有氂。',48,'全唐诗/poet.song.85000.json','["額痒會出耳，足閑仍有氂。", "石頑飛作燕，楮老孕生雞。", "楓癭那因怒，松枋豈是肥。", "君看轉丸手，亦復化神奇。"]'),
('70f2bf03-a0cf-423f-8fa3-661bb78c7ad1','示楓橋温老','孫覿','宋','宋诗','song-poetry','','[]','闔閭曾城外，寒山古道西。',48,'全唐诗/poet.song.85000.json','["闔閭曾城外，寒山古道西。", "若人具雙眼，與佛拍肩齊。", "白浪噴鷁首，黄塵送馬蹄。", "憧憧南北路，一榻有高栖。"]'),
('ba340df8-ed9d-4950-99b8-ff906c648bdb','楓橋璨書記出示近賦長句爲詩答之','孫覿','宋','宋诗','song-poetry','','[]','白㲲青鞋竹杖隨，伏犀插腦看魁奇。',64,'全唐诗/poet.song.85000.json','["白㲲青鞋竹杖隨，伏犀插腦看魁奇。", "水如說法翻千偈，山似哦詩蹙兩眉。", "率爾扣門依佛寶，欣然命駕有心期。", "匆匆班草河橋上，幾日重臨慰所思。"]'),
('9334ab11-5d9c-4aec-bd92-95691545d735','讀靈巖圓首座詩卷二首  其一','孫覿','宋','宋诗','song-poetry','','[]','長廊籍籍履聲中，邂逅歡迎得此公。',32,'全唐诗/poet.song.85000.json','["長廊籍籍履聲中，邂逅歡迎得此公。", "會續千燈齊古佛，先拈一瓣供詩翁。"]'),
('cf8906fc-4011-43d5-99d8-a09c4018b01d','讀靈巖圓首座詩卷二首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬境崩騰倒筆前，飄飄落紙似雲煙。',32,'全唐诗/poet.song.85000.json','["萬境崩騰倒筆前，飄飄落紙似雲煙。", "要看墨妙供千手，莫遣詩翁入兩肩。"]'),
('77b7a234-0d91-4a69-ac2c-96812c010f81','能仁寺悟上人來楓橋訪余索詩賦兩絕句  其一','孫覿','宋','宋诗','song-poetry','','[]','撚斷吟鬚皺兩眉，鏤冰琢雪等兒嬉。',32,'全唐诗/poet.song.85000.json','["撚斷吟鬚皺兩眉，鏤冰琢雪等兒嬉。", "解題孤月如雞口，堪笑窮郊作許悲。"]'),
('d846c546-da54-4897-9a7b-304297f14c80','能仁寺悟上人來楓橋訪余索詩賦兩絕句  其二','孫覿','宋','宋诗','song-poetry','','[]','老去都將筆硯焚，相逢相問只寒温。',32,'全唐诗/poet.song.85000.json','["老去都將筆硯焚，相逢相問只寒温。", "更無一語堪酬對，已入維摩不二門。"]'),
('9ff71833-03a6-4946-9fb6-35a9f779afd9','讀沈公序詩卷','孫覿','宋','宋诗','song-poetry','','[]','讀書過眼亦千年，脱帽揮毫湧百泉。',64,'全唐诗/poet.song.85000.json','["讀書過眼亦千年，脱帽揮毫湧百泉。", "句出驚傳龍菌蠢，賦成争誦蜺連蜷。", "銅池莖葉三山秀，玉井根株七澤連。", "容貌魁梧端可想，不應詩瘦自臞仙。"]'),
('e9869344-0af1-4eb4-b10f-254cb6a40b8a','龜潭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','擺落攀緣斷，驅除磊磈平。',48,'全唐诗/poet.song.85000.json','["擺落攀緣斷，驅除磊磈平。", "庭松敵老健，潭水伴孤清。", "待月出時看，尋雲起處行。", "相隨木上坐，徙倚到參横。"]'),
('ca2a12c8-b4c9-441a-aafc-f8a79853ad14','龜潭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','投老一無取，遊空百不聞。',48,'全唐诗/poet.song.85000.json','["投老一無取，遊空百不聞。", "莫參東閣吏，恐汙北山文。", "心定對止水，身閑臥白雲。", "嗒然吾喪我，何意傲人羣。"]'),
('1b834ca2-9b84-4962-a25e-2668764421f7','山陽守吳子仁遺兩鶴喜而賦詩二首  其一','孫覿','宋','宋诗','song-poetry','','[]','本自驂鸞駕，何因下爵羅。',48,'全唐诗/poet.song.85000.json','["本自驂鸞駕，何因下爵羅。", "未冲霄漢去，且傍水雲過。", "收拾爲閑伴，提攜作好歌。", "莫懷軒冕意，風月共婆娑。"]'),
('cbcffda3-3aa3-4ad8-8a24-b94dabfe23d0','山陽守吳子仁遺兩鶴喜而賦詩二首  其二','孫覿','宋','宋诗','song-poetry','','[]','縞袂真仙馭，玄裳羽客衣。',48,'全唐诗/poet.song.85000.json','["縞袂真仙馭，玄裳羽客衣。", "千年令威至，萬里佐卿歸。", "蹋雨青苔院，栖煙白板扉。", "蕭條真老伴，相對兩忘機。"]'),
('b604d8e0-b81e-421e-945a-4e7907540ca4','舟過湖洑泊丁山二首  其一','孫覿','宋','宋诗','song-poetry','','[]','雞犬三家市，蓬蒿一畝宮。',48,'全唐诗/poet.song.85000.json','["雞犬三家市，蓬蒿一畝宮。", "蘿牽籬羃翠，蘀隕砌堆紅。", "宿鳥來還去，微泉咽復通。", "幽尋殊未已，落日滿疏桐。"]'),
('3ce2b9f6-71ba-45ed-bc0e-92ad4cde049d','舟過湖洑泊丁山二首  其二','孫覿','宋','宋诗','song-poetry','','[]','日下殘紅斂，煙升積翠重。',48,'全唐诗/poet.song.85000.json','["日下殘紅斂，煙升積翠重。", "鷗輕波浩蕩，魚樂自從容。", "野饁迎秋穫，鄰謳相夜舂。", "田翁有真意，一笑酒中逢。"]'),
('7e735b8b-0d5d-4400-bead-fab6a03bf33c','寄題洪巨濟中大鄱陽園亭四詠 協趣亭','孫覿','宋','宋诗','song-poetry','','[]','一邱破天巧，萬壑迴春姿。',60,'全唐诗/poet.song.85000.json','["一邱破天巧，萬壑迴春姿。", "使君載酒地，不著鼓吹隨。", "翛然一幅巾，自與幽人期。", "水淺欲平杯，風細不滿旗。", "疏疏殘雨裏，獨理釣魚絲。"]'),
('2242169c-3dec-4a09-9332-7172c58283ca','寄題洪巨濟中大鄱陽園亭四詠 翠屏洞','孫覿','宋','宋诗','song-poetry','','[]','千巖紫翠中，縹緲浮畫棟。',60,'全唐诗/poet.song.85000.json','["千巖紫翠中，縹緲浮畫棟。", "屏風十二叠，坦坦見空洞。", "攢青照坐寒，老翠濕衣重。", "度曲挽雲留，舉杯邀月共。", "樂矣殊未央，正作南柯夢。"]'),
('25e5c9cb-c878-4b1f-aac7-7ee2023e55b4','寄題洪巨濟中大鄱陽園亭四詠 綠楊橋','孫覿','宋','宋诗','song-poetry','','[]','津樹正青青，水拍兩岸平。',60,'全唐诗/poet.song.86000.json','["津樹正青青，水拍兩岸平。", "千章雲外合，一勺煙中横。", "葉密翳鳥語，波清見魚行。", "灣碕雨初乾，陂露雪正晴。", "誰來聽山公，著屐過橋聲。"]'),
('1d378eda-c45e-4af5-9517-84c978b5b6be','寄題洪巨濟中大鄱陽園亭四詠 艮庵','孫覿','宋','宋诗','song-poetry','','[]','高人擅一壑，青山獨當門。',60,'全唐诗/poet.song.86000.json','["高人擅一壑，青山獨當門。", "拄笏坐終日，似與若人言。", "微雲抱巘出，細溜觸石喧。", "絕壁掛夜斗，曾甍上朝暾。", "更探東籬菊，共盡北海尊。"]'),
('b430ab61-7ce9-44fe-9381-cddc536cfb7b','春霽二首  其一','孫覿','宋','宋诗','song-poetry','','[]','好雨連清夜，寒聲滿四簷。',48,'全唐诗/poet.song.86000.json','["好雨連清夜，寒聲滿四簷。", "浣此紅點注，著柳翠條纖。", "宿潦推舟起，舂塗上屐黏。", "家家揮耒出，途詠滿蒼黔。"]'),
('7e6d834e-984a-4afc-9093-5b5905f2fd33','春霽二首  其二','孫覿','宋','宋诗','song-poetry','','[]','清飈洗睡昏，好雨愜幽欣。',48,'全唐诗/poet.song.86000.json','["清飈洗睡昏，好雨愜幽欣。", "共喜當春至，偏宜入夜聞。", "跳波通轍涸，流潤駐爐薫。", "瀲瀲沙頭綠，晴來已十分。"]'),
('144baf70-b33d-4d33-808e-0a31913e66c6','書事二首  其一','孫覿','宋','宋诗','song-poetry','','[]','坐睡抛書卷，行歌泥酒杯。',48,'全唐诗/poet.song.86000.json','["坐睡抛書卷，行歌泥酒杯。", "那能鑽故紙，莫自恥虚罍。", "閑把吟須撚，欣逢笑口開。", "獨醒竟何事，空腹吼饑雷。"]'),
('c7ff61db-84b4-4637-8816-0fb7e8bb9b29','書事二首  其二','孫覿','宋','宋诗','song-poetry','','[]','謀身殊落落，隨俗信悠悠。',48,'全唐诗/poet.song.86000.json','["謀身殊落落，隨俗信悠悠。", "但使真心住，何嫌老語偷。", "乘風豈有待，過坎且復休。", "人生如寄耳，豈恨拙于鳩。"]'),
('f82df26b-d3e4-4b1c-b5c0-cd5bb2176359','草堂路遇大風二首  其一','孫覿','宋','宋诗','song-poetry','','[]','覆地雲爲簇，填空浪作堆。',48,'全唐诗/poet.song.86000.json','["覆地雲爲簇，填空浪作堆。", "昂昂天上坐，虺虺石中雷。", "澒洞千漚發，喧豗百蟄開。", "白鷗底心性，玉羽自毰毸。"]'),
('ff723d51-886f-4f62-a3c0-63ea27134bde','草堂路遇大風二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雲屋互出沒，風扇自闔開。',48,'全唐诗/poet.song.86000.json','["雲屋互出沒，風扇自闔開。", "孤舟繫桑本，一曲並巖隈。", "翠甲連筐載，頳鱗貫柳來。", "殷勤慰牢落，爲覆掌中杯。"]'),
('6290f310-f9cd-4a6b-9319-5c933730eedb','題惠聲伯溪亭','孫覿','宋','宋诗','song-poetry','','[]','小檻大紅直欲然，喬林老翠自生煙。',64,'全唐诗/poet.song.86000.json','["小檻大紅直欲然，喬林老翠自生煙。", "雲蘿屬地青霞帔，雨筴填溝赤仄錢。", "折柳貫魚初受釣，解龜挽酒看垂蓮。", "便須秉燭追良夜，花減春歸又一年。"]'),
('9a58ac90-a2c9-4194-a983-18c7eeb671b7','雪夜宿致思庵','孫覿','宋','宋诗','song-poetry','','[]','霏霏竹間雲，練練天上雪。',60,'全唐诗/poet.song.86000.json','["霏霏竹間雲，練練天上雪。", "誰遺碧玉壺，化作白銀闕。", "孤懷愜幽欣，一笑暖栗冽。", "寒光注老眼，謂是山吐月。", "耿耿清不眠，夜半聽竹折。"]'),
('3fd13ecb-913a-4bcf-a3f3-029f82bca59b','江上懷思永二首  其一','孫覿','宋','宋诗','song-poetry','','[]','沙老猶生觜，江寒已伏槽。',48,'全唐诗/poet.song.86000.json','["沙老猶生觜，江寒已伏槽。", "長煙分聚落，短日下亭臯。", "木脱曾巢見，潮生小艇高。", "幽懷誰與悟，不見酒中豪。"]'),
('91e8eaff-b776-4f2f-bb2b-1af0d87c4d44','江上懷思永二首  其二','孫覿','宋','宋诗','song-poetry','','[]','絕徼三叉路，連艫萬斛船。',48,'全唐诗/poet.song.86000.json','["絕徼三叉路，連艫萬斛船。", "一區江上宅，百榼酒中仙。", "有土能埋玉，無膠可續絃。", "摩挲綠苔石，屐齒尚依然。"]'),
('761ebb1a-8672-4196-af04-48dcf21ed038','讀劉方叔詩卷二首  其一','孫覿','宋','宋诗','song-poetry','','[]','雄奇郊島上，清絕晉隋間。',48,'全唐诗/poet.song.86000.json','["雄奇郊島上，清絕晉隋間。", "已突黄初過，遙追正始還。", "冥搜逐幽好，巧發露天慳。", "莫作鳶肩看，詩成聳兩山。"]'),
('b72d4de7-6899-42df-97bb-46a4e5966af0','讀劉方叔詩卷二首  其二','孫覿','宋','宋诗','song-poetry','','[]','思如湧泉出，句似琢冰清。',48,'全唐诗/poet.song.86000.json','["思如湧泉出，句似琢冰清。", "刻燭翻千偈，撞鍾助一鳴。", "磨天無刃迹，擲地有金聲。", "好是銜杯處，雲煙落紙生。"]'),
('670f65cb-0c92-4b80-ab61-71eb4393d5b1','獨坐','孫覿','宋','宋诗','song-poetry','','[]','真境閑自見，衰容老更浸。',48,'全唐诗/poet.song.86000.json','["真境閑自見，衰容老更浸。", "却無愁可解，祇有病相尋。", "莫引千鈞髪，須存一寸心。", "澹然無愠喜，龜息自深深。"]'),
('4b8e870c-8976-46fe-ada2-152172755b60','正月十四日半夜大雷雨許楙仲有詩次韻三首  其一','孫覿','宋','宋诗','song-poetry','','[]','萬炬紅蓮陸海中，車如流水馬如龍。',64,'全唐诗/poet.song.86000.json','["萬炬紅蓮陸海中，車如流水馬如龍。", "九街畫鼓春聲滿，百柁瓊艘蠟味濃。", "底事狂雷翻地軸，叵堪笑電破天容。", "衝泥蹋雨尋歸路，竹杖芒鞋取次供。"]'),
('1314a439-7886-4a14-828a-3ec349b69eb4','正月十四日半夜大雷雨許楙仲有詩次韻三首  其二','孫覿','宋','宋诗','song-poetry','','[]','覆雨翻雲一霎中，雷鞭擊柱起乖龍。',64,'全唐诗/poet.song.86000.json','["覆雨翻雲一霎中，雷鞭擊柱起乖龍。", "推愁正倚三杯釅，破睡那能一枕濃。", "桑下持鉏如許健，席間失箸若爲容。", "詩翁只作啼嬰看，萬斛珠璣唾手供。"]'),
('df8aad95-3c2b-497f-bccf-3247884b34d2','正月十四日半夜大雷雨許楙仲有詩次韻三首  其三','孫覿','宋','宋诗','song-poetry','','[]','尚見暗塵隨駟馬，忽驚飛電擾羣龍。',64,'全唐诗/poet.song.86000.json','["尚見暗塵隨駟馬，忽驚飛電擾羣龍。", "玄雲合沓濤頭上，白雨渾酣乳面濃。", "淡碧鱗鱗生曉漲，小紅漠漠放春容。", "只應便作尋芳計，好把鴟夷載酒供。"]'),
('35fb2fff-2e33-4166-8cc2-ed09f9d85ec8','正月十五日荆谿館然燈燕北客用前韻','孫覿','宋','宋诗','song-poetry','','[]','虎鼠同遊十二宮，何妨蛇蚓雜蛟龍。',64,'全唐诗/poet.song.86000.json','["虎鼠同遊十二宮，何妨蛇蚓雜蛟龍。", "熒煌寶樹繁星合，泛艷金莖湛露濃。", "海鳥定知驚矍鑠，濠魚且樂共從容。", "賈生欲係單于頸，應費朝家五餌供。"]'),
('2711d017-5ca6-4c10-9393-7aed896b6c93','梅二首  其一','孫覿','宋','宋诗','song-poetry','','[]','北風翦水玉花飛，翠袖凌寒不自持。',32,'全唐诗/poet.song.86000.json','["北風翦水玉花飛，翠袖凌寒不自持。", "脉脉含情無一語，水邊籬落立多時。"]'),
('ed5ce0de-bf31-48b3-8c84-d8ecf241a64e','梅二首  其二','孫覿','宋','宋诗','song-poetry','','[]','纖纖蘿蔓牽茅屋，細細苔花點石矼。',32,'全唐诗/poet.song.86000.json','["纖纖蘿蔓牽茅屋，細細苔花點石矼。", "夢斷酒醒山月吐，一枝疏影臥東窗。"]'),
('93dec9f2-82fc-4c23-b5a1-20a4eaaa36ac','雨二首  其一','孫覿','宋','宋诗','song-poetry','','[]','風卷三江立，雷穿九地鳴。',48,'全唐诗/poet.song.86000.json','["風卷三江立，雷穿九地鳴。", "捎林百鳥散，破柱一龍驚。", "滿樹春聲合，連甍曉溜傾。", "坐看流惡盡，邑里一時清。"]'),
('4c5bc4c2-f270-4b5c-a377-296caf3b1550','雨二首  其二','孫覿','宋','宋诗','song-poetry','','[]','池涸萍黏塊，畦荒麥聚埃。',48,'全唐诗/poet.song.86000.json','["池涸萍黏塊，畦荒麥聚埃。", "乖龍一味睡，幽鳥百般催。", "藥裹蒸生菌，衣篝潤作梅。", "殷勤一夜雨，洗出翠千堆。"]'),
('70960180-5ab0-4750-ba4d-9dc62e267a20','竹間看雪二首  其一','孫覿','宋','宋诗','song-poetry','','[]','乍聞槁雪墮窗前，已見飛花舞道邊。',32,'全唐诗/poet.song.86000.json','["乍聞槁雪墮窗前，已見飛花舞道邊。", "夢斷忽驚山竹裂，一燈照我擁書眠。"]'),
('b9626a62-ec53-46fb-87d1-01f72032da5c','竹間看雪二首  其二','孫覿','宋','宋诗','song-poetry','','[]','受風豈免長低首，戴雪何妨暫折腰。',32,'全唐诗/poet.song.86000.json','["受風豈免長低首，戴雪何妨暫折腰。", "莫道此君無特操，風回雪霽便昂霄。"]'),
('169c4219-7539-47bb-90cc-f406a03032f9','題楊令藏春塢三首  其一','孫覿','宋','宋诗','song-poetry','','[]','千歲鶴林仙，故家今尚存。',48,'全唐诗/poet.song.86000.json','["千歲鶴林仙，故家今尚存。", "吟律破陰沍，扣絃召春温。", "王母仍留核，韓郎爲染根。", "暗香先到處，已返玉梅魂。"]'),
('2524e543-fe4f-48a4-9ad9-be08812cbaaf','題楊令藏春塢三首  其二','孫覿','宋','宋诗','song-poetry','','[]','汝陽紅槿帽，欲挽春風回。',48,'全唐诗/poet.song.86000.json','["汝陽紅槿帽，欲挽春風回。", "不用寶刀截，試看羯鼓催。", "玉樹日日新，金蓮步步開。", "仍須覓春草，隨人處處來。"]'),
('2bb9dfa8-01c2-4f31-888e-c188b56e6acd','題楊令藏春塢三首  其三','孫覿','宋','宋诗','song-poetry','','[]','花發武陵源，水滿藍橋路。',48,'全唐诗/poet.song.86000.json','["花發武陵源，水滿藍橋路。", "人面相映紅，迎笑得崔護。", "蜂蜨謾紛紛，尋春不知處。", "時見一葉紅，相隨水東去。"]'),
('1d7507e4-c186-4191-9b0c-5d4ad0fc80cb','累石作小山鑿池引水注之','孫覿','宋','宋诗','song-poetry','','[]','移山老翁愚，埋盆小兒嬉。',48,'全唐诗/poet.song.86000.json','["移山老翁愚，埋盆小兒嬉。", "高蹈遺世紛，幽欣可人意。", "倚樹看蜂衙，挑燈照花睡。", "樂哉何所憂，俛仰可卒歲。"]'),
('af7e3cf8-ecb4-44f5-9a3a-f884c33aa6a2','建安掾朱彦實調同安丞歸莆田枉道過余十日而别二首  其一','孫覿','宋','宋诗','song-poetry','','[]','公子命巾車，千里過我廬。',48,'全唐诗/poet.song.86000.json','["公子命巾車，千里過我廬。", "驚飛庭尉爵，喜見丈人烏。", "倚壁方挽膝，推琴欲攬須。", "殷勤更秉燭，孤悶一時攄。"]'),
('9bda589a-37e3-4107-9120-d8c13958e465','建安掾朱彦實調同安丞歸莆田枉道過余十日而别二首  其二','孫覿','宋','宋诗','song-poetry','','[]','巢枝良易安，瓢飲有餘懽。',48,'全唐诗/poet.song.86000.json','["巢枝良易安，瓢飲有餘懽。", "栖栖枳棘間，矯矯如龍鸞。", "抱牘鳧鶩進，落筆蛇蛟蟠。", "但令填紙尾，只作馬槽看。"]'),
('24744ff0-1b48-4513-8164-c130024ac85a','龜潭道中','孫覿','宋','宋诗','song-poetry','','[]','沙浄溪行好，煙消野望新。',48,'全唐诗/poet.song.86000.json','["沙浄溪行好，煙消野望新。", "數峰山戴雪，一曲塢藏春。", "魚逐波間伴，禽藏葉底身。", "柳邊春信動，眉目已津津。"]'),
('ce66c028-1c56-411b-83d8-3bb0b873ecc7','牛山道中','孫覿','宋','宋诗','song-poetry','','[]','松雲翠離披，竹日光破碎。',48,'全唐诗/poet.song.86000.json','["松雲翠離披，竹日光破碎。", "青熒麥風過，紅濕花露墜。", "萍開龜曳尾，樹啄鳥擘啄。", "物物如貺予，欣然與心會。"]'),
('9935e831-6d5e-4857-8c32-a14b9254ce90','罨畫連雨溪漲丈餘雨霽水落喜而賦詩二首  其一','孫覿','宋','宋诗','song-poetry','','[]','編栰沿村徑，囊沙壅市門。',48,'全唐诗/poet.song.86000.json','["編栰沿村徑，囊沙壅市門。", "蒼鱗封老幹，黄耳上陳根。", "屋破容身窄，天低望眼昏。", "谿邊高樹杪，猶有繫舟痕。"]'),
('7a18f0be-7f60-4139-82f1-273d78ac082a','罨畫連雨溪漲丈餘雨霽水落喜而賦詩二首  其二','孫覿','宋','宋诗','song-poetry','','[]','月挂樓鍾曉，風生島樹秋。',48,'全唐诗/poet.song.86000.json','["月挂樓鍾曉，風生島樹秋。", "林疏山獻状，池漫水分流。", "鵲喜如窺牖，鷗馴亦並舟。", "一聲何處笛，莫遣碧雲留。"]'),
('031f0e58-6816-4ec2-a5f0-5f34ea2be92c','沈公序亦愛亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','吟牽東閣興，静憩北窗眠。',48,'全唐诗/poet.song.86000.json','["吟牽東閣興，静憩北窗眠。", "窟小中生月，文高迥入玄。", "回看甲乙第，已到巳辰邊。", "不見門生莠，歌鍾尚隱然。"]'),
('076b2cbe-7bf8-4b45-87cf-5d3867ef0c79','沈公序亦愛亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','老蔓牽簷角，青蕪點石稜。',48,'全唐诗/poet.song.86000.json','["老蔓牽簷角，青蕪點石稜。", "風生長柄麈，花落短檠燈。", "危坐纔容膝，欹眠但曲肱。", "胸中九雲夢，芥蒂亦何曾。"]'),
('f9f56356-1981-4611-bf6f-e1fd679e8a20','沈公序餘閑亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','貌古鬚眉見，情高耳目遺。',48,'全唐诗/poet.song.86000.json','["貌古鬚眉見，情高耳目遺。", "應諧聊玩世，避謗莫吟詩。", "事不關心處，身非抱病時。", "翛然無一事，痛飲是吾師。"]'),
('0962d912-a1b6-4597-b954-1b559d73c56c','沈公序餘閑亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','隱几欲忘吾，趨營老更疏。',48,'全唐诗/poet.song.86000.json','["隱几欲忘吾，趨營老更疏。", "判閑聊命酒，引睡謾翻書。", "祗有貧堪逐，都無憤可攄。", "樂哉聊卒歲，應信我知魚。"]'),
('b05d2bb0-aa26-411f-b753-ee875d21753b','虎邱沼老豫章詩僧也與余相遇于楓橋方丈誦所作徐獻之侍郎生日詩有東湖孺子南極老人之句余愛其工賦小詩寄贈','孫覿','宋','宋诗','song-poetry','','[]','落景下曾城，遙煙起孤戍。',96,'全唐诗/poet.song.86000.json','["落景下曾城，遙煙起孤戍。", "繫舟著魚磯，曳杖扣僧户。", "忽逢丹霞侶，自誦碧雲句。", "噌吰應黄鍾，清絕追白紵。", "不落江西派，肯學邯鄲步。", "冥搜自天得，妙中有神助。", "寅緣半日留，邂逅一笑遇。", "詎復管中窺，看沐南山霧。"]'),
('4f475807-8060-44a4-9cf8-c938af0ce2fa','紹興壬子某南遷過疏山上一覽亭見擬東坡煨芋詩刻龕之壁間詩律句法良是殆不能辨乃宣卿侍郎守臨川時所擬作也後數日道次安仁縣一士人吳君出宣卿詩數十解示余奇麗清婉咀嚼有味如噉蔗然讀之惟恐盡於是拊卷三歎而後知公置力於斯文久矣又二十年宣卿築室荆谿山中别營一堂以平生所蓄東坡詩文雜言長短句殘章斷槀尺牘遊戲之作盡櫝藏其中號景坡自書榜仍爲記刻之某欲具小舟造觀而宣卿召用今以集撰守吳門乃賦詩爲之先','孫覿','宋','宋诗','song-poetry','','[]','王公製練衣，謝傅捉葵扇。',144,'全唐诗/poet.song.86000.json','["王公製練衣，謝傅捉葵扇。", "歘若置郵然，一昔徧海縣。", "東坡百世師，乘雲上騎箕。", "文争日月光，氣敵嵩華齊。", "諸儒望先覺，坐待成風斵。", "一斤應手揮，郢鼻無留堊。", "公生不並時，關楗同一機。", "識真屬具眼，造的今中眉。", "詩亡束晳補，書受伏生所。", "神交接混茫，參差夢中睹。", "授我筆如椽，五色光屬聯。", "醉上金鑾殿，揮泉灑謫仙。"]'),
('5e78f43d-c047-4f0d-89dc-25819a56f9dd','六言贈鶴林山長老二首  其一','孫覿','宋','宋诗','song-poetry','','[]','玄豹文章霧沐，老龍頭角泥蟠。',28,'全唐诗/poet.song.86000.json','["玄豹文章霧沐，老龍頭角泥蟠。", "莫恨青苔蹋破，要令紅柿分殘。"]'),
('ef81f5fa-f494-464d-9f16-115ed3e8c11b','六言贈鶴林山長老二首  其二','孫覿','宋','宋诗','song-poetry','','[]','黄鶴林中佛國，杜鵑花裏仙山。',28,'全唐诗/poet.song.86000.json','["黄鶴林中佛國，杜鵑花裏仙山。", "粗了一生事大，來從半日僧閑。"]'),
('50ba153b-ca39-4328-8f60-5a82624233fb','東坡先生與蔣魏公遊最善宣卿侍郎蓄東坡詩文自公始也心慕手追遂入於室某嘗賦景坡堂詩宣卿謂余知音者遂標藏之櫝中比守吳門治有狀璽書褒進待制敷文閣某馳小舟往賀宣卿出詩三章見屬句法華妙爲一時絕唱有云正索解人那復得其誰知我固無從此真東坡語也輒次韻書于卷末  其一','孫覿','宋','宋诗','song-poetry','','[]','家聲籍籍冠中州，健筆縱横貫九流。',64,'全唐诗/poet.song.86000.json','["家聲籍籍冠中州，健筆縱横貫九流。", "三世祖孫吳郡牧，兩朝人物山亭侯。", "顒卬自快披雲睹，衰陋空遺倚玉羞。", "便恐追鋒天上去，不辭投轄爲公留。"]'),
('8222fc80-b4f2-4b78-950d-7abec5bd19d1','東坡先生與蔣魏公遊最善宣卿侍郎蓄東坡詩文自公始也心慕手追遂入於室某嘗賦景坡堂詩宣卿謂余知音者遂標藏之櫝中比守吳門治有狀璽書褒進待制敷文閣某馳小舟往賀宣卿出詩三章見屬句法華妙爲一時絕唱有云正索解人那復得其誰知我固無從此真東坡語也輒次韻書于卷末  其二','孫覿','宋','宋诗','song-poetry','','[]','高名迥出中興日，大句追還正始風。',64,'全唐诗/poet.song.86000.json','["高名迥出中興日，大句追還正始風。", "浦上珠回孤月吐，壁間梭躍五雲從。", "景坡堂裏參差見，飯顆山頭邂逅逢。", "更欲騎鯨追李白，入門一路羽翰通。"]'),
('7dbfd55f-ed0a-4f26-a2ba-85198b397153','東坡先生與蔣魏公遊最善宣卿侍郎蓄東坡詩文自公始也心慕手追遂入於室某嘗賦景坡堂詩宣卿謂余知音者遂標藏之櫝中比守吳門治有狀璽書褒進待制敷文閣某馳小舟往賀宣卿出詩三章見屬句法華妙爲一時絕唱有云正索解人那復得其誰知我固無從此真東坡語也輒次韻書于卷末  其三','孫覿','宋','宋诗','song-poetry','','[]','洲蘂霏紅風澹沱，池光鋪練月徘徊。',64,'全唐诗/poet.song.86000.json','["洲蘂霏紅風澹沱，池光鋪練月徘徊。", "乍驚醉眼生春纈，頓覺詩腸蟄夜雷。", "坐看千言供刻燭，自甘百罰恥空罍。", "使君處處栽桃李，爲報花奴羯鼓催。"]'),
('d0cc3419-ad6e-4792-9e50-befd19261c2c','景思提舉少卿出示藥寮佳篇某繼元韵上呈','孫覿','宋','宋诗','song-poetry','','[]','連筒自灌黄精圃，結轍休推薏苡車。',64,'全唐诗/poet.song.86000.json','["連筒自灌黄精圃，結轍休推薏苡車。", "萬壑飛泉舂午枕，一簑带雨荷春鋤。", "逃名尚有身爲累，擇利焉知貨可居。", "笑指吳公門上莠，一時零落已邱墟。"]'),
('5419b3af-ab4f-4b48-99d8-fae5d881d1ed','與季萬郎中陪景思少卿遊虎邱景思季萬皆有詩某依韻和呈 次景思少卿韻','孫覿','宋','宋诗','song-poetry','','[]','客來聽履上雲階，百尺蒼藤絡斷崖。',64,'全唐诗/poet.song.86000.json','["客來聽履上雲階，百尺蒼藤絡斷崖。", "古井千年龍上臥，層邱一曲虎爲儕。", "乍驚河漢懸談舌，便覺風雲入壯懷。", "小雨隨車真有意，待催詩板挂高齋。"]'),
('d406c226-48af-49b9-88f4-d3abcca8c1f3','與季萬郎中陪景思少卿遊虎邱景思季萬皆有詩某依韻和呈 次季萬郎中韻','孫覿','宋','宋诗','song-poetry','','[]','玉梯一蹴傍天閽，歷歷星圖手可捫。',64,'全唐诗/poet.song.86000.json','["玉梯一蹴傍天閽，歷歷星圖手可捫。", "翠濕佛衣雲漠漠，香凝僧幌雨昏昏。", "曾軒下瞰三吳小，靈阜高齊五岳尊。", "大句舂容兩相敵，暫陪尊酒得重論。"]'),
('ee22f5ce-e9cf-4e19-b262-d1f8f627f3e5','謝景思提舉見過用藥寮韻賦三詩寄謝  其一','孫覿','宋','宋诗','song-poetry','','[]','璽書光麗九芝塗，繡斧煌煌刺史車。',64,'全唐诗/poet.song.86000.json','["璽書光麗九芝塗，繡斧煌煌刺史車。", "當路狐狸那足問，漫山藜藿未應鉏。", "使星尚供天南極，卿月終環帝北居。", "此夜光華賁岑寂，故侯留落在郊墟。"]'),
('5b4f84ae-68fd-41b3-85ff-4255534c6446','謝景思提舉見過用藥寮韻賦三詩寄謝  其二','孫覿','宋','宋诗','song-poetry','','[]','屋頭遙見丈人烏，門外欣逢載酒車。',64,'全唐诗/poet.song.86000.json','["屋頭遙見丈人烏，門外欣逢載酒車。", "拄杖穿林花自落，攜壺席地草休鉏。", "褰帷共看高軒過，列戟行歸大府居。", "掣電一歡寧復有，空傳勝事滿村墟。"]'),
('04740758-733e-4791-8268-a8df0913a2a4','謝景思提舉見過用藥寮韻賦三詩寄謝  其三','孫覿','宋','宋诗','song-poetry','','[]','行把長鑱白木柄，慵眠下澤短轅車。',64,'全唐诗/poet.song.86000.json','["行把長鑱白木柄，慵眠下澤短轅車。", "柳圍許大身空老，瓜地將蕪手自鉏。", "三徑苔荒無轍跡，一枝巢隱有林居。", "故人觸熱來相問，終日清風滿廢墟。"]'),
('22cce547-875e-40d7-b773-942f6e494405','提刑直閣張公挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','荷鍤酬身後，騎箕返帝旁。',48,'全唐诗/poet.song.86000.json','["荷鍤酬身後，騎箕返帝旁。", "風纒卿月暈，雲掩使星光。", "炯炯三珠在，冥冥一鑑亡。", "故交今白髮，掩映涕淋浪。"]'),
('0214c131-da6e-4673-98b1-7e12234383c8','提刑直閣張公挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','無事空心折，懷新尚目存。',48,'全唐诗/poet.song.86000.json','["無事空心折，懷新尚目存。", "壽康駢五福，德爵擅三尊。", "蠹落芸籖冷，蛛懸畫戟昏。", "像圖猶彷彿，謾寄刻舟痕。"]'),
('6aad3a62-1235-4ede-b65e-1b481938d5d7','致政中奉胡公挽詞','孫覿','宋','宋诗','song-poetry','','[]','釣石駸駸上綠苔，起彈長鋏詠歸哉。',64,'全唐诗/poet.song.86000.json','["釣石駸駸上綠苔，起彈長鋏詠歸哉。", "此翁矍鑠丹心在，老子婆娑兩鬢催。", "一夜劍津龍化後，千年遼海鶴歸來。", "匆匆鼓吹城南路，往和松風萬壑哀。"]'),
('16ccbcc2-0b3d-461f-b56c-61437d360f2c','黄州使君朝議惠公挽詞','孫覿','宋','宋诗','song-poetry','','[]','墨榜書名萬口傳，著鞭爭看祖生先。',64,'全唐诗/poet.song.86000.json','["墨榜書名萬口傳，著鞭爭看祖生先。", "一揮禮樂三千字，獨擅文章二百年。", "晚得朱輪今老矣，生存華屋尚依然。", "故交掩袂追疇昔，一劍空留宰樹邊。"]'),
('5b163674-5d77-4de1-8c3a-759cdbab82e9','吳公宜人楊氏挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','零落藁砧非，猶殘淚滿衣。',48,'全唐诗/poet.song.86000.json','["零落藁砧非，猶殘淚滿衣。", "三刀悲尚在，雙劍喜同歸。", "地占眠牛卜，門迎弔鶴飛。", "哀哉埋玉樹，千古悶泉扉。"]'),
('2d80be89-be5b-4a67-8a48-aaade144e1e5','吳公宜人楊氏挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','種玉滿家庭，聲名重十城。',48,'全唐诗/poet.song.86000.json','["種玉滿家庭，聲名重十城。", "哀矜游子線，愁絕小人羮。", "贈印連三組，書名載一旌。", "誰爲千字誄，彷彿記平生。"]'),
('5db124f4-1b0f-41ab-be81-5ffedcac82d5','致政運使直閣朱公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','握節來金馬，飛芻上木牛。',48,'全唐诗/poet.song.86000.json','["握節來金馬，飛芻上木牛。", "能令天粟雨，故作地錢流。", "望實傾三館，賢勞閲百州。", "寥寥千古恨，零落掩山邱。"]'),
('1859b394-6bad-4f21-abf5-788f3e969546','致政運使直閣朱公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','蕭散烏藤杖，風流白接離。',48,'全唐诗/poet.song.86000.json','["蕭散烏藤杖，風流白接離。", "分茵前席滿，載酒後車隨。", "食鼎羅千指，歌鍾擁十眉。", "凄凉今夜月，空照習家池。"]'),
('2ae3a8f0-515d-4a3b-8928-ad7df92ccd36','致政運使直閣朱公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','老脱尚方舄，門懸刺史車。',48,'全唐诗/poet.song.86000.json','["老脱尚方舄，門懸刺史車。", "真成棄竹馬，直欲換金魚。", "歲事千頭橘，生涯萬卷書。", "流芳知未艾，蘭玉滿階除。"]'),
('f2f32f19-6a84-4fa1-8c71-0548dbf7f9ea','致政左司王公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','東海懷疏傅，西州憶謝公。',48,'全唐诗/poet.song.86000.json','["東海懷疏傅，西州憶謝公。", "劍飛衝夜斗，桂折臥秋風。", "塵暗芸堂冷，香凝粉署空。", "潺潺千斛淚，忍看一旌紅。"]'),
('712b8f9e-b46a-4ff1-8907-637ed2835e02','致政左司王公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','解組天門上，揮金里舍傍。',48,'全唐诗/poet.song.86000.json','["解組天門上，揮金里舍傍。", "漸欣雙髀滿，仍見一瞳方。", "舊說山中相，今爲地下郎。", "流芳知有在，鸞鵠正高翔。"]'),
('0a025fd3-19fc-4c4a-9c56-6aa53d84b130','致政左司王公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','憶昨聯飛蓋，初筵點後塵。',48,'全唐诗/poet.song.86000.json','["憶昨聯飛蓋，初筵點後塵。", "那知炊未熟，已與迹俱陳。", "契闊成千古，悲吟待百身。", "重臨更愁絕，感塞鼻中辛。"]'),
('71ec39b9-b93e-448d-a52c-22113c2647fa','天台太守端明吳公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','天上文昌省，人中翰墨仙。',48,'全唐诗/poet.song.86000.json','["天上文昌省，人中翰墨仙。", "尚書心似水，學士筆如椽。", "視草金蓮夜，哦詩錦瑟年。", "玉樓方斷手，又著紫鸞鞭。"]'),
('654f8abb-2260-41f0-ad6a-d51784fa7cac','天台太守端明吳公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','遮門皓首啼，行路涕交揮。',48,'全唐诗/poet.song.86000.json','["遮門皓首啼，行路涕交揮。", "不見斑衣好，空隨畫翣歸。", "蘭芽方獨秀，華萼尚交輝。", "試待遼東鶴，千年有令威。"]'),
('2b1c27a1-b3a9-4ec4-b49d-dbb7b70b106e','天台太守端明吳公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','貧病見交情，殷勤問死生。',48,'全唐诗/poet.song.86000.json','["貧病見交情，殷勤問死生。", "倒衣迎五馬，空巷看雙旌。", "聚泛杯中月，分班地上荆。", "悲吟追往事，感咽氣峥嶸。"]'),
('c1a80498-76d4-417d-8310-a39badb2796b','宣撫簽樞胡公挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','幕府分弓日，轅門叱馭時。',48,'全唐诗/poet.song.86000.json','["幕府分弓日，轅門叱馭時。", "捫星高歷井，修月上騎箕。", "剺面降胡泣，聞鼙聖主思。", "龍驤老賓客，競賦八哀詩。"]'),
('7f355739-8347-4ba8-9a6f-1daf9ffbdc75','宣撫簽樞胡公挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','交親二紀餘，貧病故人疏。',48,'全唐诗/poet.song.86000.json','["交親二紀餘，貧病故人疏。", "落落辰參似，寥寥楚越如。", "空勞三夜夢，不辨一行書。", "尚記喬公約，垂洟滿過車。"]'),
('bf3fa7eb-2989-4d61-b160-77a63c4f0ad2','張希元承事挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','秀髮豪眉覆兩顴，身長九尺地行仙。',64,'全唐诗/poet.song.86000.json','["秀髮豪眉覆兩顴，身長九尺地行仙。", "楚人尚記庚寅日，晉客渾疑甲子年。", "批鳯璽書光洗眼，刻鳩靈杖穩隨肩。", "世人欲計吾公事，膝上郎君雪滿顛。"]'),
('47d666e1-f06e-4ffd-acf8-914f7727525b','張希元承事挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','門外魌頭引葬簫，寥寥繐帳北山椒。',64,'全唐诗/poet.song.86000.json','["門外魌頭引葬簫，寥寥繐帳北山椒。", "槐宫一夢驚三世，蓂殿千齡數七朝。", "此夜騎星上南極，他年跨鶴下東遼。", "摩挲銅狄長安道，試問飛車儻可招。"]'),
('d9429e6d-c026-4187-9226-adcecc9254b1','提刑郎中范公挽詞','孫覿','宋','宋诗','song-poetry','','[]','星軺出帝躔，光射斗牛邊。',72,'全唐诗/poet.song.86000.json','["星軺出帝躔，光射斗牛邊。", "納陛傾三接，埋輪聳十連。", "那知憂鵩日，已復夢鷄年。", "尚遂斑衣戲，俄從白布纒。", "倚閭心破碎，投袂涕潺湲。", "更有門前客，愁吟淚滿牋。"]'),
('e2a6ba74-7f95-4c18-bd81-5f5262e14d0e','越國鄭夫人挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','翁婿相望插兩貂，夫人東第閲三朝。',64,'全唐诗/poet.song.86000.json','["翁婿相望插兩貂，夫人東第閲三朝。", "百年鍾鼎聯雙璧，一代衣冠繼八蕭。", "盡室全生還帝所，先生遺烈在天驕。", "家傳故有緇衣在，且看司徒首百寮。"]'),
('11a1fcc5-2681-4e0c-84e0-9c76c633d3ff','越國鄭夫人挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','舊德遺忠在禁庭，天教華髮看昇平。',64,'全唐诗/poet.song.86000.json','["舊德遺忠在禁庭，天教華髮看昇平。", "兩朝偃革從今日，百口同袍共此生。", "喜見金葩開大國，悲傳玉樹鎖佳城。", "魌頭直指西州路，獵獵秋風載一旌。"]'),
('48d271cd-d717-4602-a431-f29b6d199c02','吏部張公挽詞','孫覿','宋','宋诗','song-poetry','','[]','千騎森森擁戟牙，鈴齋高臥放朝衙。',64,'全唐诗/poet.song.86000.json','["千騎森森擁戟牙，鈴齋高臥放朝衙。", "官曹已踐文昌省，門闕猶傳處士家。", "天上麒麟新活計，壁間蝌蚪舊生涯。", "一炊未熟成今古，零落空懸刺史車。"]'),
('46dd4d8d-cca9-4be5-8754-276e882c2f35','致政中大邵公挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','四海聲名老鄭虔，一時人物敢争先。',64,'全唐诗/poet.song.86000.json','["四海聲名老鄭虔，一時人物敢争先。", "剖符北道分千里，擁節東州按十連。", "住世一丸無大藥，傳家三絕有遺編。", "魌頭直指山南去，昨夜秋風正颯然。"]'),
('089f64ea-5a50-4992-b1f1-7941b551b4bb','致政中大邵公挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','憶從少日望前修，追數流年四十秋。',64,'全唐诗/poet.song.86000.json','["憶從少日望前修，追數流年四十秋。", "並轡同遊天上路，連檣共載雪中舟。", "傷心往事千憂結，回首勞生一夢休。", "見說騎鯨追汗漫，只將遺蜕掩山邱。"]'),
('e6d756fb-c8de-4ba0-acc4-7420e9d16eeb','光禄董公挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','舊學江都相，遺忠太史家。',48,'全唐诗/poet.song.86000.json','["舊學江都相，遺忠太史家。", "絳帷今寂寞，青簡尚光華。", "謾奏三千牘，猶傳四十車。", "諸生半齊魯，東望涕横斜。"]'),
('b0ac096d-9404-42e6-b049-e6c15d68a100','光禄董公挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','帳殿旌旗卷，轅門鼓角悲。',48,'全唐诗/poet.song.86000.json','["帳殿旌旗卷，轅門鼓角悲。", "江邊五馬渡，天上六龍飛。", "感憤冠衝髮，追攀肘見衣。", "興元戡難日，零落寸心違。"]'),
('3db727aa-28a9-4d78-8871-70a25f34593c','董夫人挽詞','孫覿','宋','宋诗','song-poetry','','[]','象服夫人貴，荆釵烈女風。',48,'全唐诗/poet.song.86000.json','["象服夫人貴，荆釵烈女風。", "生兒真孟母，擇婿得梁鴻。", "書費囊衣盡，杯行澗藻豐。", "龍池飛霹靂，雙劍已騰空。"]'),
('5ffc12b3-1079-4622-8dd6-9fbcfd59c5d4','董令人李氏挽詞','孫覿','宋','宋诗','song-poetry','','[]','閬苑收花去，無心對紫薇。',48,'全唐诗/poet.song.86000.json','["閬苑收花去，無心對紫薇。", "寥寥鶴夜怨，角角雉朝飛。", "石窌名猶在，邯鄲夢已非。", "郎君真驥子，玉立換朝衣。"]'),
('b7753f2f-94b9-40ac-9cb2-91ec262f1017','惠彦達承事挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','鳩杖尊三壽，龜床閲九齡。',48,'全唐诗/poet.song.86000.json','["鳩杖尊三壽，龜床閲九齡。", "名留高士傳，光掩少微星。", "圯下無遺躅，江邊有獨醒。", "潭潭餘慶在，鸞鵠滿家庭。"]'),
('6f6071d2-57ba-4eba-9d01-b02e8e984992','惠彦達承事挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','逐客生還後，臞翁耄及時。',48,'全唐诗/poet.song.86000.json','["逐客生還後，臞翁耄及時。", "長鳴風雨夜，耐老歲寒枝。", "坐閲炎凉改，寧隨燥濕移。", "隻鷄澆斗酒，敢忘故人期。"]'),
('12cab8f0-55cb-40bd-bce5-4d6eb4d15493','大資政張公挽詞四首  其一','孫覿','宋','宋诗','song-poetry','','[]','大筆文章手，飛揚獨妙年。',48,'全唐诗/poet.song.86000.json','["大筆文章手，飛揚獨妙年。", "判花森玉笋，視草對金蓮。", "講肄聯重席，官花臥八磚。", "他年紬石室，妙絕冠遺編。"]'),
('57163d7d-2f33-4c91-9812-0eeaa8ae4172','大資政張公挽詞四首  其二','孫覿','宋','宋诗','song-poetry','','[]','禮絕迂三顧，恩榮閲九遷。',48,'全唐诗/poet.song.86000.json','["禮絕迂三顧，恩榮閲九遷。", "秉均平似砥，履坦直如弦。", "晉室和戎日，周家定鼎年。", "金甌方卜相，飊馭已超然。"]'),
('ba6f8a4e-1822-4bf5-9d69-2f998e862fc2','大資政張公挽詞四首  其三','孫覿','宋','宋诗','song-poetry','','[]','大閥冠州閭，占星太史書。',48,'全唐诗/poet.song.86000.json','["大閥冠州閭，占星太史書。", "萬蹄金騕褭，一角玉蟾蜍。", "右輔開新府，東堂舊直廬。", "凄涼便陳迹，彷彿夢華胥。"]'),
('9a1ca151-a582-4511-872e-37206d0c6536','大資政張公挽詞四首  其四','孫覿','宋','宋诗','song-poetry','','[]','輦路追高躅，聯翩接兩騶。',48,'全唐诗/poet.song.86000.json','["輦路追高躅，聯翩接兩騶。", "猶蟠倚天劍，尚艤濟川舟。", "元帥俄分閫，羈臣亦首邱。", "一抔相屬地，回首涕交流。"]'),
('c4e5797d-c196-47cc-a0d2-4c0cebc87e99','侍郎唐公挽詞','孫覿','宋','宋诗','song-poetry','','[]','危言屢伏青蒲上，直筆猶存白簡中。',64,'全唐诗/poet.song.86000.json','["危言屢伏青蒲上，直筆猶存白簡中。", "但見刳蟆救月蝕，孰知煉石補天空。", "牛鳴尚鬬床頭蟻，蛇影猶懸屋底弓。", "一代風流今頓盡，佳城白日臥滕公。"]'),
('699b8f4c-ee7a-44a4-aedf-95be94f384ff','洪內翰母夫人董氏挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','鳲鳩一德本來均，七子劬勞詠棘薪。',64,'全唐诗/poet.song.86000.json','["鳲鳩一德本來均，七子劬勞詠棘薪。", "種玉已成雙白璧，起家還見十朱輪。", "鼇扉獨步中興日，麟閣他年第幾人。", "送客誰爲千家誄，要看彤筆寫光塵。"]'),
('3670170c-3fc2-4d60-aa20-fe666f27e804','洪內翰母夫人董氏挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬里龍沙握鼠餘，古來忠孝兩全無。',64,'全唐诗/poet.song.86000.json','["萬里龍沙握鼠餘，古來忠孝兩全無。", "范滂死去親猶在，蘇武生還老益孤。", "旄節盡從蠻檄落，綵衣重向鯉庭趨。", "天敎住世如金母，一笑迎還合浦珠。"]'),
('2524e4b5-7bce-4e0a-b5bc-f31af36ad25b','簽書胡公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','潤色文章手，論材政事科。',48,'全唐诗/poet.song.86000.json','["潤色文章手，論材政事科。", "補天媧后石，却日魯侯戈。", "已鬱蒼生望，那聞挽者歌。", "堂堂無復有，寂寞閟山阿。"]'),
('26de15e4-cd53-40f2-97b9-f39e2be8bed9','簽書胡公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','虎穴連三輔，狼煙暗百蠻。',48,'全唐诗/poet.song.86000.json','["虎穴連三輔，狼煙暗百蠻。", "邊風搖馬鬛，朔雪點袍斑。", "委命輕於縞，收名重若山。", "遺忠應未泯，結草在兵間。"]'),
('6450edf6-0752-49b0-8f11-f7a21e54f528','簽書胡公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','名字標仙籍，真遊返帝闉。',48,'全唐诗/poet.song.86000.json','["名字標仙籍，真遊返帝闉。", "一尊無復日，百卉自争春。", "井廢無沈轄，車懸有吐茵。", "空餘峴山刻，千載尚光新。"]'),
('d4836cfd-2143-49a9-98c8-9a7c5a1f4138','平江太守侍郎王公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','燕頷封侯相，鷹揚國士風。',48,'全唐诗/poet.song.86000.json','["燕頷封侯相，鷹揚國士風。", "金貂七葉貴，鼓角十州雄。", "按節星軺動，埋輪虎穴空。", "誰令交一臂，已失大槐宫。"]'),
('4c0239a6-5955-49f9-a5e3-5b48119b7dce','平江太守侍郎王公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','東吏重足立，無家寄一錐。',48,'全唐诗/poet.song.86000.json','["東吏重足立，無家寄一錐。", "道旁烏攫肉，舍下犬生氂。", "望絕重臨日，哀吟去後思。", "吳兒奉嘗我，歌此送迎詩。"]'),
('c0a84dae-f311-4e8e-84b4-ce615f493d04','平江太守侍郎王公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','通德門中見，長安道上逢。',48,'全唐诗/poet.song.86000.json','["通德門中見，長安道上逢。", "虚名慚薦鶚，喜色看乘龍。", "流落湘江魄，崎嶇楚市舂。", "相看青眼舊，獨有後凋松。"]'),
('12d41056-5339-40b7-a1a7-1eb8342c56ff','嬴國夫人錢氏挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','大國侯王後，高門將相家。',48,'全唐诗/poet.song.86000.json','["大國侯王後，高門將相家。", "欲知天作合，故遣壽無涯。", "夢澤萍如斗，仙山棗似爪。", "鶴林花老去，歸路躡青霞。"]'),
('d6e6e068-e3de-45f9-b9cd-b33bbcac5c38','嬴國夫人錢氏挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','鼎立三珠樹，亭亭聳縉紳。',48,'全唐诗/poet.song.86000.json','["鼎立三珠樹，亭亭聳縉紳。", "真成萬金産，何止十朱輪。", "彤筆方紬史，芝塗尚演綸。", "徽音千載後，不數衛夫人。"]'),
('4f75f16f-e960-4968-8f7a-615be0785963','朝議胡公挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','魁壘萬夫雄，堂堂望一宗。',48,'全唐诗/poet.song.86000.json','["魁壘萬夫雄，堂堂望一宗。", "名聯千佛土，籍著九圍重。", "月旦推三鳯，風流屬二龍。", "哀哉埋玉樹，一塢閟金鍾。"]'),
('e396c197-056a-409c-864b-cec240dac4ab','朝議胡公挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','巨室蔭華榱，驚聞一柱摧。',48,'全唐诗/poet.song.86000.json','["巨室蔭華榱，驚聞一柱摧。", "辛勤三世種，寂寞萬牛回。", "猶抱萊衣泣，俄興楚挽哀。", "功名付難弟，榮路正崔嵬。"]'),
('429aeaa0-aafc-4399-84cd-789209c2301d','霍彦明通判挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','龍飛第一春，吏部冠斯文。',48,'全唐诗/poet.song.86000.json','["龍飛第一春，吏部冠斯文。", "桂折根猶在，蘭深氣自薫。", "未成觀驥展，已復嘆芝焚。", "想像今何在，江東有暮雲。"]'),
('e2b48326-21e1-4622-9afc-2cae8b5a3f4e','霍彦明通判挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','契闊艱虞地，匆匆喜一逢。',48,'全唐诗/poet.song.86000.json','["契闊艱虞地，匆匆喜一逢。", "俄驚門上莠，已化柙中龍。", "手板歸囊禇，腰章掩窆封。", "空餘故人淚，灑向九泉重。"]'),
('34ac4248-42da-436e-b31d-6c80b17d42a1','邵令人余氏挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','身老偕三壽，家肥賦萬鍾。',48,'全唐诗/poet.song.86000.json','["身老偕三壽，家肥賦萬鍾。", "給扶靈杖穩，賜禮紫泥封。", "青冢連雙璧，蒼精蟄二龍。", "春風吹宰樹，蕭颯壠頭松。"]'),
('4d81872c-b9fa-46dd-8d2f-42c2690b8d3b','邵令人余氏挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','金母燕西瑤，朱幩翟茀朝。',48,'全唐诗/poet.song.86000.json','["金母燕西瑤，朱幩翟茀朝。", "遺衣尚荆布，故物有簞瓢。", "鼎立栖三鳯，蟬聯數七貂。", "生涯祗如此，崛鬱正昂霄。"]'),
('e7653990-21da-4f1c-a38a-509f8f9fc29b','太令人施氏挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','天上驂鸞鶴，人中夢虺蛇。',48,'全唐诗/poet.song.86000.json','["天上驂鸞鶴，人中夢虺蛇。", "舒長真化國，青白舊儒家。", "朝籍通丹地，宫衣曳紫霞。", "蓬萊三萬里，何處問靈槎。"]'),
('821ecc28-499d-47b8-b43e-d01e02d9de70','太令人施氏挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','領袖三千指，恩斯母德均。',48,'全唐诗/poet.song.86000.json','["領袖三千指，恩斯母德均。", "奇龐五世祖，福艾百年身。", "零落悲華屋，劬勞詠棘薪。", "誰當紬女史，彤筆寫光塵。"]'),
('40c08806-bd07-423e-835c-78f056e4f48f','通川太守錢公挽詞','孫覿','宋','宋诗','song-poetry','','[]','舞鳯來天目，馮熊並海門。',48,'全唐诗/poet.song.86000.json','["舞鳯來天目，馮熊並海門。", "盡捐牛犢佩，争詠袴襦恩。", "雁塔名猶在，棠郊苃故存。", "龍池飛霹靂，空記刻舟痕。"]'),
('af6fe663-f1b9-44fb-806c-f49879a5da30','王廷秀挽詞','孫覿','宋','宋诗','song-poetry','','[]','朱雀烏衣巷，青袍白首郎。',48,'全唐诗/poet.song.86000.json','["朱雀烏衣巷，青袍白首郎。", "誰令呼起起，便作去堂堂。", "急景駒跳隙，哀音雁折行。", "慶鍾知有在，庭樹正流芳。"]'),
('fae3ebcc-6122-40c1-be5d-f0c58983a7cb','吳令人挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','誰識東床臥，相隨廡下舂。',48,'全唐诗/poet.song.86000.json','["誰識東床臥，相隨廡下舂。", "懸知三復可，不恨五噫從。", "玉冠螭頭立，芝塗玳首封。", "諸兒荀淑侣，頭角盡羣龍。"]'),
('4defd9f8-2df7-4a3a-973d-b376a2aa28ae','吳令人挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','沄沄水東注，冉冉日西頽。',48,'全唐诗/poet.song.86000.json','["沄沄水東注，冉冉日西頽。", "側手留難住，揮戈挽莫迴。", "鏡分天上月，劍逸地中雷。", "寂歷空牀夜，悲蟲亦造哀。"]'),
('10e4c5b0-9621-4df0-ba9a-89355039ef95','歷陽通守張文舉挽詞','孫覿','宋','宋诗','song-poetry','','[]','六雄唐别駕，一乘漢題輿。',48,'全唐诗/poet.song.86000.json','["六雄唐别駕，一乘漢題輿。", "自笑儒冠誤，誰能刺繡如。", "彤襜方首路，畫翣已隨車。", "悵望城南陌，哀歌淚滿裾。"]'),
('677f6e65-099c-4834-8ad2-b8e6255eed20','通守李師稷大夫同年挽詞','孫覿','宋','宋诗','song-poetry','','[]','桂籍聯榮四十年，萍漂南北兩茫然。',64,'全唐诗/poet.song.86000.json','["桂籍聯榮四十年，萍漂南北兩茫然。", "寒暄粗接無淹晷，生死俄分有逝川。", "黄紙尚傳批鳯詔，青箱空掩絕韋編。", "諸郎頭角皆翁似，試看煎膠爲續絃。"]'),
('211660f0-be69-40be-930e-d6ed25261e9b','王廷茂挽詞','孫覿','宋','宋诗','song-poetry','','[]','蟬聯三世舊，晼晼二毛侵。',48,'全唐诗/poet.song.86000.json','["蟬聯三世舊，晼晼二毛侵。", "白璧成長慟，青綸遂陸沈。", "看雲空有淚，聽雨若爲心。", "咽咽吹簫送，哀湍共一音。"]'),
('8e4f4080-3c09-430c-872f-65dcdd35a328','大卿范公師厚挽詞','孫覿','宋','宋诗','song-poetry','','[]','籍甚金閨彦，從容玉帳籌。',72,'全唐诗/poet.song.86000.json','["籍甚金閨彦，從容玉帳籌。", "垂堂懲後戒，徙突慕前修。", "忽作隋珠彈，真成趙璧投。", "寧辭廣武械，竟脱楚儀囚。", "蹇叔言猶在，殽函骨未收。", "云何即長夜，不復見焚舟。"]'),
('30016ac7-6eb1-41d9-acbd-623126af33ab','孫應求承事挽詞','孫覿','宋','宋诗','song-poetry','','[]','棣萼聯華滿故枝，蘭芽競秀藹春霏。',64,'全唐诗/poet.song.86000.json','["棣萼聯華滿故枝，蘭芽競秀藹春霏。", "荆州司馬馮熊去，吳市仙人跨鶴歸。", "綠漲一枝分柏壟，遙蒼百叠擁松扉。", "儀形故有丹青在，想像平生果是非。"]'),
('3e2e60c1-51fb-4267-ba3f-2d42943e160b','吳漢逸挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','臞翁自是列仙儒，豪氣駸駸若不除。',64,'全唐诗/poet.song.86000.json','["臞翁自是列仙儒，豪氣駸駸若不除。", "東閣尋梅詩滿篋，西郊問柳酒盈車。", "奇礓屢訪陳倉鼓，古漆空存汲冢書。", "不信青山解埋玉，定應碧海控鯨魚。"]'),
('d583a969-58cc-4959-830d-8a7822aa9d59','吳漢逸挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','學省追攀四十年，故人重見兩皤然。',64,'全唐诗/poet.song.86000.json','["學省追攀四十年，故人重見兩皤然。", "艱難共出興戎後，奄忽安知棄我先。", "北道改轅誰解劍，西州無路相鳴鞭。", "傷心一夢成今古，忍看麒麟臥冢邊。"]'),
('6df9dddb-5f9e-4885-9798-da05c2c1e64d','寶文李公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','十道觀風使，三朝屬老成。',48,'全唐诗/poet.song.86000.json','["十道觀風使，三朝屬老成。", "埋輪豺虎避，檄水鰐魚驚。", "內閣徴書入，連城負弩迎。", "哀吟追往事，空復故人情。"]'),
('e8cd2476-6f3d-4824-b885-6b5f8134c8b0','寶文李公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','絳雪飛丹鼎，蒼雲覆茗杯。',48,'全唐诗/poet.song.86000.json','["絳雪飛丹鼎，蒼雲覆茗杯。", "聊從五禽戲，空使萬牛回。", "拄笏看山坐，乘桴跨海來。", "仙遊知有在，名字記丹臺。"]'),
('187f8ec4-e4ed-4975-9c73-d2c67a061189','寶文李公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','五紀周旋地，欣同七十稀。',48,'全唐诗/poet.song.86000.json','["五紀周旋地，欣同七十稀。", "長庚陪月曉，孤鶩伴霞飛。", "忽作三休去，真成一夢非。", "不知華表上，白鶴幾時歸。"]'),
('374397b5-6157-4eaa-898a-eb44533213cd','邵久中承事挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','周分陜右開燕日，秦廢侯家徙漢年。',64,'全唐诗/poet.song.86000.json','["周分陜右開燕日，秦廢侯家徙漢年。", "南國棠陰猶蔽芾，東陵爪蔓正芊綿。", "蒼波吐月珠還浦，紫電衝星劍倚天。", "藉甚公孫望千載，書藏萬卷有青氈。"]'),
('6263fbaa-d66d-4ed9-a8a9-ce293ff0260f','邵久中承事挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','手扶棁杖兩眉厖，牀下諸生拜老龐。',64,'全唐诗/poet.song.86000.json','["手扶棁杖兩眉厖，牀下諸生拜老龐。", "講肆共推三語妙，詩壇獨受百城降。", "揮金屢費青錢萬，種玉親收白璧雙。", "一臥遽先朝露盡，便隨晨鼓去逢逢。"]'),
('d85b4dd1-f65f-4dd2-874e-e0544992c343','邵久中承事挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','尺書問信墨猶新，杯酒邀歡跡已陳。',64,'全唐诗/poet.song.86000.json','["尺書問信墨猶新，杯酒邀歡跡已陳。", "倒屣方追塵外躅，蓋棺俄作地中身。", "濤江灔灔三家渡，風樹蕭蕭萬鬼鄰。", "他日故人千斛淚，會應灑向冢邊麟。"]'),
('b8d7e3f8-da9e-4837-92e6-8cdb3f45a4a9','張大資夫人挽詞','孫覿','宋','宋诗','song-poetry','','[]','早歲乘龍見伯鸞，賜衣霞爛出齊官。',64,'全唐诗/poet.song.86000.json','["早歲乘龍見伯鸞，賜衣霞爛出齊官。", "自從東閣郎君貴，只作西池阿母看。", "紫玉簫吹丹鳯去，青萍劍合兩蛟蟠。", "素車白馬城南路，愁見春風桂影團。"]'),
('54925b2e-b8ee-4089-9006-505c9e001eef','族嬸强氏挽詞','孫覿','宋','宋诗','song-poetry','','[]','少日聲名推大阮，一時門地數南强。',64,'全唐诗/poet.song.86000.json','["少日聲名推大阮，一時門地數南强。", "家肥自稱河魴貴，廟薦猶聞澗藻香。", "羽化忽驚雙鶴去，巢空不復九雛將。", "歸魂無用哀笳送，彷彿吹簫在帝鄉。"]'),
('f0e212ab-288e-435c-9c6c-a62e615d9ffc','王令人蔡氏挽詞','孫覿','宋','宋诗','song-poetry','','[]','殿極中台應，淮流奕世祥。',72,'全唐诗/poet.song.86000.json','["殿極中台應，淮流奕世祥。", "佳兒王武子，名父蔡中郎。", "傳葉青氈在，談經絳幔張。", "懸知黑頭貴，已佇白眉良。", "蘋老那能采，萱留祗自芳。", "誰當授彤筆，端爲刻青琅。"]'),
('15d97a1f-4e5f-4ec8-bf12-8223d5bef6f5','少保張公挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','帝閫謀元師，齋壇屬老儒。',48,'全唐诗/poet.song.86000.json','["帝閫謀元師，齋壇屬老儒。", "黄麻孚大號，皂纛擁前驅。", "便合聯黄袞，猶應冠紫區。", "炎炎白晝日，奄忽下桑榆。"]'),
('0c6e4ae5-e22c-47b2-949e-d362249256e3','少保張公挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','平土疏新渥，湛恩洞九泉。',48,'全唐诗/poet.song.86000.json','["平土疏新渥，湛恩洞九泉。", "印懸金斗大，冠珥玉蟬連。", "墜劍今亡矣，鳴珂尚宛然。", "風流春月柳，無復似當年。"]'),
('dacdc2bd-45ec-4cc8-80d3-22ffc08cd2ca','少保張公挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','並轡天街里，聯裾省户中。',48,'全唐诗/poet.song.86000.json','["並轡天街里，聯裾省户中。", "追參兩班合，醉笑一尊同。", "我老猶占鵩，公豪正吐虹。", "忽騎箕尾去，悽斷白頭翁。"]'),
('9f627444-c352-41bc-bd1b-34c2ec91ede0','周撫幹挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','手植千金産，情高一笑揮。',48,'全唐诗/poet.song.86000.json','["手植千金産，情高一笑揮。", "懷奇空老去，種德自家肥。", "聯艦收羣溺，傾囷振大饑。", "誰云天未定，一鶚已横飛。"]'),
('8479fa31-5f98-4743-ae3e-38a57c3408b7','周撫幹挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','誰續先賢傳，猶推月旦評。',48,'全唐诗/poet.song.86000.json','["誰續先賢傳，猶推月旦評。", "命儒通德里，聽法梵王城。", "除地黄金布，帷裳絳帳横。", "何人追舊事，扣角話三生。"]'),
('66e58a60-38e6-40f4-be36-c7e85825551f','領省樞相太傅信安王挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','臺路巖瞻峻，戎藩閫寄雄。',48,'全唐诗/poet.song.86000.json','["臺路巖瞻峻，戎藩閫寄雄。", "九章公袞貴，六纛將牙崇。", "翊運三階正，持危一棟隆。", "帝閑龍化后，冀北已成空。"]'),
('6fc52864-45e3-4c90-a482-4ca29f629501','領省樞相太傅信安王挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','大號疏廷渙，中權秉帝樞。',48,'全唐诗/poet.song.86000.json','["大號疏廷渙，中權秉帝樞。", "槐庭聯上宰，芸省冠諸儒。", "國瑞麟一角，家肥鳯九雛。", "便乘箕尾去，彷彿在星圖。"]'),
('0daec380-53f7-4023-b05a-697905759e9d','領省樞相太傅信安王挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','秉燭聯飛蓋，分茵託後車。',48,'全唐诗/poet.song.86000.json','["秉燭聯飛蓋，分茵託後車。", "兵廚千日酒，記室五雲書。", "尚想儀形在，那聞語笑餘。", "龍鍾隨葬紼，老淚滿衣裾。"]'),
('003ab6ba-4efa-4ad9-95a4-f642a9aa29b6','永嘉郡夫人挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','脂田開石窌，綸閣演金葩。',48,'全唐诗/poet.song.86000.json','["脂田開石窌，綸閣演金葩。", "綵服聯三組，褕衣珥六珈。", "行攜九節杖，坐駕五雲車。", "便坐堂堂去，瑤臺有故家。"]'),
('3977a82f-8a51-40e5-83b7-c9871b04d6f3','永嘉郡夫人挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','蔽芾斗城春，平反迹未陳。',48,'全唐诗/poet.song.86000.json','["蔽芾斗城春，平反迹未陳。", "神馳一丹旐，淚濕兩朱輪。", "故物悲萱草，哀吟念棘薪。", "室傳青簡上，千載望光塵。"]'),
('b30dda6e-aae1-448f-9d36-c4d938df85a5','運使直閣郎中張公同年挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','忽作霜松折，猶殘舊桂叢。',48,'全唐诗/poet.song.86000.json','["忽作霜松折，猶殘舊桂叢。", "仙山芸閣冷，郎署粉闈空。", "節蕩函金虎，車轓掩畫熊。", "凄凉追往事，忍看一旌紅。"]'),
('21f8916c-c648-4513-a124-2210f6bcbaf9','運使直閣郎中張公同年挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','門表尚巍昂，尊名擅一坊。',48,'全唐诗/poet.song.86000.json','["門表尚巍昂，尊名擅一坊。", "珂鳴非故里，星聚有新堂。", "月暗烏啼夜，風高雁折行。", "吾生如寄耳，端是橘中藏。"]'),
('8c8dc6b2-28fb-491b-8ef4-31879383971f','運使直閣郎中張公同年挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','學省周旋地，三朝四紀中。',48,'全唐诗/poet.song.86000.json','["學省周旋地，三朝四紀中。", "同聽對床雨，共詠舞雩風。", "少日借千佛，殘年獨兩翁。", "那知有存沒，老淚落新宫。"]'),
('dec2368c-041b-414e-904c-167977373411','魯國太夫人文氏挽詞三首  其一','孫覿','宋','宋诗','song-poetry','','[]','席寵千齡盛，疏榮一品尊。',48,'全唐诗/poet.song.86000.json','["席寵千齡盛，疏榮一品尊。", "魏公丞相婦，潞國太師孫。", "連騎珂鳴里，交柯戟擁門。", "平生種玉手，盡室滿瑤琨。"]'),
('dd860a67-71ac-43b1-909c-3dfc254ef39f','魯國太夫人文氏挽詞三首  其二','孫覿','宋','宋诗','song-poetry','','[]','移孝繄慈母，遺忠有世臣。',48,'全唐诗/poet.song.86000.json','["移孝繄慈母，遺忠有世臣。", "挺身安國步，抗節犯戎塵。", "錫壤開東魯，持樞拱北辰。", "寧須待彤筆，詔墨在絲綸。"]'),
('4e2a2abe-116d-40ce-b027-046236bd4fbb','魯國太夫人文氏挽詞三首  其三','孫覿','宋','宋诗','song-poetry','','[]','鼎餗羞嘉饗，溪毛薦德馨。',48,'全唐诗/poet.song.86000.json','["鼎餗羞嘉饗，溪毛薦德馨。", "來符虺蛇夢，去囁鳯凰翎。", "盛事垂千載，華年閲九齡。", "凄凉便塵迹，柏壟自青青。"]'),
('11c5a286-e621-49e4-a06c-7704201536aa','過洞庭','孫覿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','千尺銀山屹嵩華，浪涌雲屯天一罅。',128,'全唐诗/poet.song.86000.json','["千尺銀山屹嵩華，浪涌雲屯天一罅。", "榜舟夜傍黿鼉窟，杖藜曉入雞豚社。", "處處人家橘柚垂，竹籬茅屋青黄亞。", "臺殿青紅墜半山，兩腋清風策高駕。", "牛羊出沒怪石走，蛟蛇起伏蒼藤掛。", "饑鼠窺燈佛帳寒，華鯨吼粥僧趺下。", "世味飽諳真嚼蠟，老境得閑如啗蔗。", "山靈知我欲歸耕，一夜筑垣應繞舍。"]'),
('e733133b-42b6-4148-8728-efa19855ad26','中興頌','孫覿','宋','宋诗','song-poetry','','[]','水部天寶中興碑，浯溪摩崖天與齊。',128,'全唐诗/poet.song.86000.json','["水部天寶中興碑，浯溪摩崖天與齊。", "龍亡虎逝今已矣，太宗社稷猶巍巍。", "泗濱九鼎不復出，陳倉石鼓今已非。", "巋然獨立湘水上，往往或有神司之。", "我亦繫舟石壁下，老眼驚顧眩欲迷。", "星圖錯落樹掛斗，雲物黯淡天投霓。", "遺忠寂寂閟千載，山頹木壞知河□。", "踟躕對立三太息，風雨夜嘯猩鼯悲。"]'),
('1390fa2b-5ec2-4add-bb01-173e506faf80','樞密胡公進諸子于學年方冠強記博覽穎悟過人某每過公清夫廉夫立侍公側賦巨題押強韻率有奇語嘆愛之余作詩傳坐客云','孫覿','宋','宋诗','song-poetry','','[]','于菟生而斑，騏子墮地走。',119,'全唐诗/poet.song.86000.json','["于菟生而斑，騏子墮地走。", "眈眈百獸長，矯矯六龍友。", "家庭傳吉夢，釋氏曾抱送。", "英英玉雪如，連璧見二仲。", "讀書夜不眠，歷歷數十年。", "吟成一寸燭，笑拍郊賀肩。", "聚訟破三語，下筆先風雨。", "妙句出錦囊，陳言陋鹽絮。", "辟易四坐驚，難弟有兄。", "傳觀莫放手，擲地有金聲。"]'),
('0475e683-9e3f-442a-8d77-5ff023ef9689','和叔毅田園五首  其一','孫覿','宋','宋诗','song-poetry','','[]','投組棄不御，負耒行且耰。',48,'全唐诗/poet.song.86000.json','["投組棄不御，負耒行且耰。", "頹景謝東嵎，新畬遍西疇。", "煙墟牛羊夕，水島橘柚秋。", "呼兒具雞黍，一醉漫爛酬。"]'),
('1d8029de-383c-4ef2-87f3-839d9d3f7c3b','和叔毅田園五首  其二','孫覿','宋','宋诗','song-poetry','','[]','休文固多病，長卿亦倦游。',48,'全唐诗/poet.song.86000.json','["休文固多病，長卿亦倦游。", "敢厭蓬蓽陋，漸喜桑榆收。", "散策塵外往，脫屐區中留。", "坐看黄葉落，一洗風雨秋。"]'),
('36bd9183-2c18-4a45-be9e-548f4a58e8f4','和叔毅田園五首  其三','孫覿','宋','宋诗','song-poetry','','[]','風旗喜初泊，野馬不受鞿。',36,'全唐诗/poet.song.86000.json','["風旗喜初泊，野馬不受鞿。", "萬里漲江急，一棹秋風歸。", "意行心自放，隅坐談更劇。"]'),
('48468200-edfd-40e9-ad94-d624f8f62f6e','和叔毅田園五首  其四','孫覿','宋','宋诗','song-poetry','','[]','晨耕饁簞壺，夜績課絺綌。',48,'全唐诗/poet.song.86000.json','["晨耕饁簞壺，夜績課絺綌。", "感時百憂集，遇酒一笑適。", "五湖波浪闊，勿厭田廬窄。", "土膏燥不粘，山骨寒更瘠。"]'),
('4cafc091-5aaa-4928-bb01-ad31bd990721','和叔毅田園五首  其五','孫覿','宋','宋诗','song-poetry','','[]','傷心離離黍，觸目青青穸。',36,'全唐诗/poet.song.86000.json','["傷心離離黍，觸目青青穸。", "空畦理荒穢，流潤滋霖霡。", "努力會有年，喜見乞漿客。"]'),
('1e4335a8-810d-40d1-8d84-29071b19d94f','得子次叔毅韻','孫覿','宋','宋诗','song-poetry','','[]','病木空中穴萬蟻，龍臥泥蟠鞭不起。',129,'全唐诗/poet.song.86000.json','["病木空中穴萬蟻，龍臥泥蟠鞭不起。", "老氣干霄四十圍，雷折蒼皮半生耳。", "人言種木十年期，桐已生孫竹有兒。", "添丁哇笑已堪喜，老幹輪囷只自奇。", "刀頭舐空虛何草草，平地變作褒斜道。", "我獨愛之遺以安，家住鹿門山安逸。", "阿奴碌碌在眼中，逢時不願黑頭公。", "三尺茅茨十具牛，不如長作多田翁。"]'),
('6ecbec23-ecd9-4ddd-b0c4-4bb6123d5de9','閱古閣','孫覿','宋','宋诗','song-poetry','','[]','勸君慎莫學爲儒，令君甑釜生蟲魚。',96,'全唐诗/poet.song.86000.json','["勸君慎莫學爲儒，令君甑釜生蟲魚。", "啼饑號寒祇四壁，拄腹撐腸謾五車。", "鄧侯種德如種木，千金買書書滿屋。", "縹緲玉京十二樓，縱橫牙籤三萬軸。", "鄱陽太守筆如椽，雄文大字青瑤鐫。", "千載風流追峴首，名字永與羊公傳。"]'),
('02a52ce8-b9bb-467e-8d00-62453ca465ed','何利見新居四詠 種德堂','孫覿','宋','宋诗','song-poetry','','[]','種德固自期百年，陰功可以宥十世。',64,'全唐诗/poet.song.86000.json','["種德固自期百年，陰功可以宥十世。", "地靈崛鬰蔭萬家，門大崢嶸納千駟。", "老椿已老臥山根，戢戢階庭滿蘭蕙。", "王郎故有青氈存，鄭公又改緇衣敝。"]'),
('80bb26b1-54ab-4089-ba3f-da82b239737f','何利見新居四詠 停雲閣','孫覿','宋','宋诗','song-poetry','','[]','桃李臥開櫻半吐，嗟我懷人道伊阻。',64,'全唐诗/poet.song.86000.json','["桃李臥開櫻半吐，嗟我懷人道伊阻。", "偶來見此衣上雲，忽去已作山下雨。", "青青可藉草忘憂，昵昵如聞花解語。", "舉鞭試問並州兒，酩酊醉翁在何許。"]'),
('3eb3c296-2830-4915-98e1-84174eef363b','何利見新居四詠 偃寂軒','孫覿','宋','宋诗','song-poetry','','[]','玉輅親巡萬里沙，金鞭斷折五侯家。',64,'全唐诗/poet.song.86000.json','["玉輅親巡萬里沙，金鞭斷折五侯家。", "胡塵闐空箭滿眼，天地黤慘推龍蛇。", "何郎築室山間曲，桃花流水空藏遮。", "一榻清風駕兩腋，尚嫌蟻鬬靜中譁。"]'),
('e62ebbbc-32e4-4a3f-9a2d-441be77a60cf','何利見新居四詠 燕起軒','孫覿','宋','宋诗','song-poetry','','[]','竹塢松窗靜者居，醉鄉一夢追華胥。',64,'全唐诗/poet.song.86000.json','["竹塢松窗靜者居，醉鄉一夢追華胥。", "亂山攢青靄崷崒，老樹偃翠橫扶疏。", "主人投轄防客走，醉倒自有蛾眉扶。", "爍爍籠燈紅一朵，孤芳獨自占春餘。"]'),
('41426d8d-d923-4c05-be47-b899a517fe83','祥符寺大梅一樹臨水初開','孫覿','宋','宋诗','song-poetry','','[]','石梁茆屋雨蒼苔，春風一笑冰容開。',64,'全唐诗/poet.song.86000.json','["石梁茆屋雨蒼苔，春風一笑冰容開。", "微瀾浸月臥疏影，一枝的皪橫江海。", "含情不語立雪久，飛步欲去凌波回。", "紛紛紅紫莫浪出，我欲楚些招歸來。"]'),
('7b4192af-f5e5-4506-ac37-ee8b2ffdf187','宿天寧寺','孫覿','宋','宋诗','song-poetry','','[]','屋漏我無愧，室暗那可欺。',72,'全唐诗/poet.song.86000.json','["屋漏我無愧，室暗那可欺。", "老僧對清夜，淛風動伽梨。", "諄諄面牆壁，皎皎分澠淄。", "燎蚊隔煙語，聞雞起蓐炊。", "我來何所見，興盡意輒隨。", "相逢不相識，聊問姓名誰。"]'),
('65771a19-8209-458f-b74d-8381d5bae879','次苦竹渡','孫覿','宋','宋诗','song-poetry','','[]','浮雲漲天黑，鍛此百鍊兵。',72,'全唐诗/poet.song.86000.json','["浮雲漲天黑，鍛此百鍊兵。", "匣臥韜白月，手揮沸奔星。", "風塵劍三尺，削盡多壘平。", "往往失其柄，倒戈來抗衡。", "養虎恐遺患，媚蟆終自盲。", "君子善藏之，綠林正橫行。"]'),
('de381751-22f2-4736-9950-008ea38fc9b3','簡澤民','孫覿','宋','宋诗','song-poetry','','[]','窮途棲棲傍阡陌，俗態紛紛斗筲窄。',64,'全唐诗/poet.song.86000.json','["窮途棲棲傍阡陌，俗態紛紛斗筲窄。", "殺牛毀車欲何向，握食解驂誰召客。", "吾髯一諾黄金百，醉溺應憐厠中客。", "蕭蕭窮巷席爲門，不信陳平死糠覈。"]'),
('77a16610-81de-409c-bdda-fab9af061b43','誦次魏詩','孫覿','宋','宋诗','song-poetry','','[]','歌終白玉爛，夢覺黄糧熟。',96,'全唐诗/poet.song.86000.json','["歌終白玉爛，夢覺黄糧熟。", "斯人已寂寥，皎皎在空谷。", "誰令黔首愚，竟坐城旦讀。", "光芒豐城劍，慟哭荆山玉。", "鄒郎乃其徒，閱世何燭局。", "高風渺不嗣，句法此遺躅。", "火攻真下策，弔古悼秦俗。", "驪山一炬燔，雞林萬金贖。"]'),
('4e398668-92ca-4a0d-ba28-8b36b624ecf9','示長文','孫覿','宋','宋诗','song-poetry','','[]','于公種陰德，門大端可期。',120,'全唐诗/poet.song.86000.json','["于公種陰德，門大端可期。", "無錢囊更空，有子家自肥。", "戢戢樹九畹，濯濯秀一枝。", "坐客矚青眼，餘子讓白眉。", "鹽絮出妙語，春草先夢思。", "詩文未可量，家學豈其師。", "五車儻足用，萬里到不疑。", "非無昂父賢，且伴濟叔癡。", "芝蘭莫當戶，桃李自成蹊。", "它年一樽酒，名與少陵齊。"]'),
('3ad81415-0e0c-4a3a-8533-148dd135da24','郭守冰花詩','孫覿','宋','宋诗','song-poetry','','[]','雲藏紅樹三生緣，地涌青蓮諸佛現。',96,'全唐诗/poet.song.86000.json','["雲藏紅樹三生緣，地涌青蓮諸佛現。", "又見冰華此夜開，一蓋亭亭倚天半。", "月中桂樹影婆娑，海底珊瑚光璀璨。", "褰簾已化白銀闕，照室盡成青玉案。", "懸知不受衆目憐，端爲使君娛一盼。", "何用孤松腹上生，行向三槐庭下見。"]'),
('01bc6578-45cb-4ffc-b8ec-36ecd37d1c07','武進王丞二首 欣榮亭','孫覿','宋','宋诗','song-poetry','','[]','客有倦游者，置居在西疇。',72,'全唐诗/poet.song.86000.json','["客有倦游者，置居在西疇。", "平生會心處，高引寄一丘。", "吟窗山入坐，釣瀨雪滿舟。", "更秉西園燭，寬我千歲憂。", "仍傾中山酒，澆此萬斛愁。", "出門何所詣，真欲老菟裘。"]'),
('b32d02bf-8eec-42da-b6d6-f5dd990f31d1','武進王丞二首 告春亭','孫覿','宋','宋诗','song-poetry','','[]','東皋有佳致，中夜雨一犁。',72,'全唐诗/poet.song.86000.json','["東皋有佳致，中夜雨一犁。", "喜笑作春聲，麥塊青欲齊。", "淺瀨發清響，陳根出新荑。", "紅情顔未破，□顰眉上低。", "練巾已堪岸，藜杖始一攜。", "殷勤遺好音，胡蘆來勸提。"]'),
('d8541047-9a5d-417b-8cb1-1d8e8bfff5cc','全州道中','孫覿','宋','宋诗','song-poetry','','[]','桑柘十里交，烏犍隨兩童。',48,'全唐诗/poet.song.86000.json','["桑柘十里交，烏犍隨兩童。", "川平牛背穩，一笛橫秋風。", "漠漠水雲裏，濛濛煙雨中。", "人牛相爾汝，行過亂山東。"]'),
('de8ea837-5925-4b26-9423-d966b81a2c47','豐績堂','孫覿','宋','宋诗','song-poetry','','[]','驚沙撲面犬羊腥，坐嘯胡床卻五兵。',64,'全唐诗/poet.song.86000.json','["驚沙撲面犬羊腥，坐嘯胡床卻五兵。", "未忍焚廬攻腐鼠，要須劈水膾長鯨。", "收身且護千金璧，琢句尤夸五字城。", "築室掛冠真漫耳，麒麟圖畫有高營。"]'),
('0045c4ea-0e1b-4e24-84ae-2b64e4da2b02','寒食','孫覿','宋','宋诗','song-poetry','','[]','月落烏啼古木昏，宿雲未歛日光暾。',96,'全唐诗/poet.song.86000.json','["月落烏啼古木昏，宿雲未歛日光暾。", "閉門喧豗百賈鬧，塵埃一覺車雲奔。", "據鞍已覺朝市遠，細路漸入桑麻村。", "累累青冢繄蓬顆，風掃露沐松爲門。", "魂飛骨冷喚不覺，隻雞斗酒聊相溫。", "種種閑情便愁絕，行歌野哭不堪聞。"]'),
('debb9f95-8455-4ada-8cf3-828aaee83d6d','舟次寧陵','孫覿','宋','宋诗','song-poetry','','[]','萬舸連檣夜鳴柝，舟師鼻鼾風雷惡。',96,'全唐诗/poet.song.86000.json','["萬舸連檣夜鳴柝，舟師鼻鼾風雷惡。", "何人勃窣夜深行，微步凌波上船閣。", "駸駸舐紙欲窺窗，稍稍開扃見門鑰。", "櫜空甑倒無一錐，暗裏不堪供摸索。", "吠形時聽犬吽呀，戒曉已聞雞呃喔。", "人窮智□亦可憐，與汝徒行吾更怍。"]'),
('cc6a3191-e7ee-4bc1-b3b2-7080278f6e81','泊陳留','孫覿','宋','宋诗','song-poetry','','[]','野水半篙碧，釀成歸意濃。',48,'全唐诗/poet.song.86000.json','["野水半篙碧，釀成歸意濃。", "繁霜挾夜氣，微露點秋容。", "嚼蠟有何好，嘗膽聊自攻。", "翛然發深省，不待五更鍾。"]'),
('3ad211ad-c5d6-4e40-8c08-514c73527eba','奉祠朝日飲卯酒就寢既覺庭中蕭然已無行跡馬上賦詩','孫覿','宋','宋诗','song-poetry','','[]','蕭晨按節齊房弭，冠蓋環趍垤爭蟻。',64,'全唐诗/poet.song.86000.json','["蕭晨按節齊房弭，冠蓋環趍垤爭蟻。", "屐聲籍籍海上潮，人語喧喧日中市。", "明朝途人踐芻狗，雲散風休真夢爾。", "不須強記刻舟痕，滿地蒼苔餘屐齒。"]'),
('362a0309-a2a3-46bb-90b9-dda9e212999c','讀范周士詩卷二首  其一','孫覿','宋','宋诗','song-poetry','','[]','客舍空山裏，叢祠古道旁。',48,'全唐诗/poet.song.86000.json','["客舍空山裏，叢祠古道旁。", "飄飄雲外思，兀兀酒中藏。", "巧麗詩無敵，驚窺首一昂。", "緘封休浪出，珍重錦爲囊。"]'),
('3e1e7917-2a2d-4929-9e96-b82ca9e8c08a','讀范周士詩卷二首  其二','孫覿','宋','宋诗','song-poetry','','[]','汗血蒼龍種，名翬紫鳳毛。',48,'全唐诗/poet.song.86000.json','["汗血蒼龍種，名翬紫鳳毛。", "赤霄行未穩，白雪句先高。", "月斧將誰斷，風斤可獨操。", "雄夸賦雲夢，莫學楚臣騷。"]'),
('a4ec6a89-c08b-4754-a7f2-6de60b92eff8','送陳令解印赴闕三首  其一','孫覿','宋','宋诗','song-poetry','','[]','戶外瓏璁響玉珂，弁星遙見切雲峨。',64,'全唐诗/poet.song.86000.json','["戶外瓏璁響玉珂，弁星遙見切雲峨。", "蝸泉渺渺依龍具，鳬影翩翩下雀羅。", "溜雨霜皮青嶂合，摶風雲翮紫霄摩。", "八門了了登天路，一夜驚雷起壁梭。"]'),
('26fdeb6a-147f-42f1-b9f6-1880a1c4a202','送陳令解印赴闕三首  其二','孫覿','宋','宋诗','song-poetry','','[]','帳殿籌兵擁俊髦，風塵三尺劍吹毛。',64,'全唐诗/poet.song.86000.json','["帳殿籌兵擁俊髦，風塵三尺劍吹毛。", "鸞旂低繞金輿動，雉扇旁連玉簡高。", "折柳便堪當馬箠，割雞何足試牛刀。", "看君一掃欃槍盡，歸握元戎虎豹韜。"]'),
('4dd34b43-90fe-4724-9dfc-3aaaa951f265','送陳令解印赴闕三首  其三','孫覿','宋','宋诗','song-poetry','','[]','亂山環合水邊村，楚些誰招九死魂。',64,'全唐诗/poet.song.86000.json','["亂山環合水邊村，楚些誰招九死魂。", "鳥語遷枝黄葉□，蝸涎粘壁古苔昏。", "禾囷屢出將軍指，菜把空懷地主恩。", "落日秋風滿山色，盡驅離恨入清罇。"]'),
('762322bd-2fac-4217-9023-339194ce7f7d','胥澤民竹亭','孫覿','宋','宋诗','song-poetry','','[]','兵氣纏三輔，胡塵暗百蠻。',120,'全唐诗/poet.song.86000.json','["兵氣纏三輔，胡塵暗百蠻。", "楚狂歌鳳去，蜀相臥龍跧。", "露蘚霾松磴，春羅掛屋山。", "呼童開翠竹，築室待蒼彎。", "碧瀉褰羅带，青遙聳髻鬟。", "森羅隨地闢，披寫露天慳。", "川泳知魚樂，林栖看鳥還。", "醉吟呼酒伴，逸想寄人寰。", "北海摶風背，南山浴露班。", "弓旌到林下，鞍馬出門閑。"]'),
('c451be4a-baaf-4393-8a39-4a9eee7629d9','與李彥能范安同赴澤民之集飯後野步','孫覿','宋','宋诗','song-poetry','','[]','提壺聲裏有嘉招，步屐尋芳過小橋。',64,'全唐诗/poet.song.86000.json','["提壺聲裏有嘉招，步屐尋芳過小橋。", "萬壑春風笑笙籟，一溪晴日碎瓊瑤。", "虺隤未忍加鞭去，磊塊惟愁着酒澆。", "雲月娟娟弄人影，醉歸扶路莫辭遙。"]'),
('16956608-7b16-4351-9321-f0fcc8a16f03','次韻周士春晴二首','孫覿','宋','宋诗','song-poetry','','[]','門鵠猶殘雪，林鶯已喚春。',96,'全唐诗/poet.song.86000.json','["門鵠猶殘雪，林鶯已喚春。", "相逢青眼見，不恨白頭新。", "獵獵翻歸袖，僛僛落醉巾。", "小紅齊破蕾，一笑爲何人。", "綠漲三家渡，紅酣萬戶春。", "交情久客見，物態一時新。", "縹緲凌波襪，淋漓漉酒巾。", "對花身已在，應解笑陳人。"]'),
('00380aa8-eb45-4981-ba68-8d6f01becb53','次韻王子欽妙覺新居','孫覿','宋','宋诗','song-poetry','','[]','苔花带雨上秋床，欹枕無人午夢長。',64,'全唐诗/poet.song.86000.json','["苔花带雨上秋床，欹枕無人午夢長。", "愁極俱憑詩可遣，憂深唯有酒能忘。", "窺人谷鳥怱怱語，撲馬巖花細細香。", "袖手莫夸窮事業，試將斗酒換西涼。"]'),
('32658fe5-543a-4862-a01a-1d4e9037cf5a','題范周士瀟湘圖','孫覿','宋','宋诗','song-poetry','','[]','平生千里目，遙寓紫翠間。',48,'全唐诗/poet.song.86000.json','["平生千里目，遙寓紫翠間。", "見此紙上語，照我胸中山。", "泛泛水俱遠，悠悠雲共閑。", "漁翁收晚釣，一棹醉中還。"]'),
('66d93d3d-5c04-4246-83a4-b313e69758fd','齊雲樓','孫覿','宋','宋诗','song-poetry','','[]','他日羣偷窺撲滿，旱時遣患識金仙。',64,'全唐诗/poet.song.86000.json','["他日羣偷窺撲滿，旱時遣患識金仙。", "頹基尚带三江水，故苑今隨一炬煙。", "駒隙未過人換世，棠陰不剪樹參天。", "從今免被元龍笑，茅屋三間蔽采椽。"]'),
('2c7d48cb-10f0-4925-862b-8ee656b089e1','虎丘','孫覿','宋','宋诗','song-poetry','','[]','夢裏清游一瞬間，苔留屐齒尚班班。',63,'全唐诗/poet.song.86000.json','["夢裏清游一瞬間，苔留屐齒尚班班。", "千章古木禿如赭，百尺老蛟寒跧。", "徑欲乘桴蹈東海，那能拄笏望西山。", "人間俯仰成今古，青冢累累鶴未還。"]'),
('0a4288a7-51b3-4f1a-9fb3-e1bbe9c3f72b','靈巖','孫覿','宋','宋诗','song-poetry','','[]','青蓮花出古娃宮，華殷亭亭月滿容。',64,'全唐诗/poet.song.86000.json','["青蓮花出古娃宮，華殷亭亭月滿容。", "風籟一聲傳夜壑，雲幢千丈蔭蒼松。", "曲池漫漫悲禾黍，古隧冥冥出鼎鍾。", "落紙煙雲供醉筆，吾宗文采擅雕龍。"]'),
('312b8b11-41ed-4609-91df-741488dc4c5e','次韻蔣次莊二首  其一','孫覿','宋','宋诗','song-poetry','','[]','敝裘羸馬老風塵，兩鬢星星亂白綸。',64,'全唐诗/poet.song.86000.json','["敝裘羸馬老風塵，兩鬢星星亂白綸。", "乘興來尋剡溪雪，倦游歸釣錦江春。", "眼中了了三生夢，俗眼欣欣一笑親。", "急雨催詩頭上黑，憑誰喚起謫仙人。"]'),
('6b554978-48d0-4541-a53c-6046d739f698','次韻蔣次莊二首  其二','孫覿','宋','宋诗','song-poetry','','[]','政拙心勞愧此身，一麾便合掛朝紳。',64,'全唐诗/poet.song.86000.json','["政拙心勞愧此身，一麾便合掛朝紳。", "青山有意迎仙客，白日相逢是故人。", "見說卑宮恢禹迹，時來擊壤頌堯仁。", "玉川寸鐵真無用，地上空愁蟣蝨臣。"]'),
('d34cbc43-77fc-49e1-9f90-aafecb2d3c6f','思上人休菴二首  其一','孫覿','宋','宋诗','song-poetry','','[]','置屋蒼崖上，騎鯨碧海中。',48,'全唐诗/poet.song.86000.json','["置屋蒼崖上，騎鯨碧海中。", "築閑樵徑雨，門掩釣船風。", "蟻穴封千戶，蝸廬鬬兩雄。", "區區真可笑，天地一塵中。"]'),
('d59fc50e-8da9-4f9b-b74d-2b02f5322c44','思上人休菴二首  其二','孫覿','宋','宋诗','song-poetry','','[]','閱世身如夢，捐書語更真。',48,'全唐诗/poet.song.86000.json','["閱世身如夢，捐書語更真。", "人牛俱不見，棒喝總休親。", "敗壁蟲書蘚，空床鼠印塵。", "滔滔天下士，應不羨知津。"]'),
('f4e61bcc-0507-413a-978a-948176b69e41','次魏惠書二小詩代簡  其一','孫覿','宋','宋诗','song-poetry','','[]','劍臥衝星斗，珠璣照海涯。',48,'全唐诗/poet.song.86000.json','["劍臥衝星斗，珠璣照海涯。", "籋雲梢驥足，擘水拔鯨牙。", "議論輕餘子，文章自一家。", "堂堂楚雲夢，給札賦雄夸。"]'),
('efff03e4-2f40-482a-b20b-f81b4d804ac8','次魏惠書二小詩代簡  其二','孫覿','宋','宋诗','song-poetry','','[]','飄飄遷客去，戀戀故人心。',48,'全唐诗/poet.song.86000.json','["飄飄遷客去，戀戀故人心。", "墨妙傳雙鯉，情高敵萬金。", "天旋黄道直，野迥白沙沉。", "不負青雲意，繄君嗣好音。"]'),
('5cd88ff6-0a78-4933-bbff-250115b13c15','和劉守林宗喜晴二首  其一','孫覿','宋','宋诗','song-poetry','','[]','禾頭生耳釜生魚，去馬來牛迥不殊。',64,'全唐诗/poet.song.86000.json','["禾頭生耳釜生魚，去馬來牛迥不殊。", "颶勢驅雲千嶂合，雷公載雨百車輪。", "長堤一決無完塊，高樹紛披有積蘇。", "賴有媧皇補天手，一時爭誦魯真儒。"]'),
('c35c80ce-d8a0-44b5-a911-edcf556301ab','和劉守林宗喜晴二首  其二','孫覿','宋','宋诗','song-poetry','','[]','滌地愁霏欲變魚，毗耶問疾有文殊。',64,'全唐诗/poet.song.86000.json','["滌地愁霏欲變魚，毗耶問疾有文殊。", "擬將十萬回天去，且罄丹衷伏地輸。", "忽聽風聲傳畫角，徐看日影上流蘇。", "麴窮不用號眢井，呫囁瘦詞笑小儒。"]'),
('8a671ea2-5a12-484f-8b83-07bb4b2bf925','強氏園亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','綠漲柳塘漫，紅翻花徑深。',48,'全唐诗/poet.song.86000.json','["綠漲柳塘漫，紅翻花徑深。", "意行留勝踐，孤悶破芳斟。", "倦馬縻空櫪，驚烏泊晚林。", "潭潭萬人海，理策又歸尋。"]'),
('da7e0ebf-e481-4a04-b002-ae26da17bb2a','強氏園亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','柳外楓橋轉，桑間竹徑分。',48,'全唐诗/poet.song.86000.json','["柳外楓橋轉，桑間竹徑分。", "意行穿竹過，小雨隔溪聞。", "日萼團紅糝，風漪織翠紋。", "不知誰主客，相值兩孤雲。"]'),
('b19a07e7-86e8-4ca7-8ba1-c170526cde38','立秋日次韻葛正卿','孫覿','宋','宋诗','song-poetry','','[]','侵曉微雲渡，秋聲带雨來。',48,'全唐诗/poet.song.86000.json','["侵曉微雲渡，秋聲带雨來。", "池涼噤蛙鼓，簾靜閟蚊雷。", "風伯褰帷入，炎官叱馭回。", "不須移枕簟，揮塵謝徘徊。"]'),
('cc88a59d-fcb6-4fea-ac79-1a3d13dab39f','次韻叔毅兄佳什','孫覿','宋','宋诗','song-poetry','','[]','雲夢平吞八九寬，紫髯紅頰秀春巒。',64,'全唐诗/poet.song.86000.json','["雲夢平吞八九寬，紫髯紅頰秀春巒。", "天邊鴻雁心應折，竿上鯨鯢肉未寒。", "倦聽山城鳴鼓角，喜瞻衡宇掛衣冠。", "培風好上天南去，莫遣荆榛簉孔鸞。"]'),
('2872f3d6-9fbf-4fe2-9672-fe4196365c53','感春四首  其一','孫覿','宋','宋诗','song-poetry','','[]','槿籬茆屋兩三家，急雨捎谿燕子斜。',64,'全唐诗/poet.song.86000.json','["槿籬茆屋兩三家，急雨捎谿燕子斜。", "萬壑笙鏞號地籟，一天繒絮墮楊花。", "風塵澒洞身先老，樽酒歡呼氣尚華。", "虎穴參差半朝市，無嫌卑濕賦長沙。"]'),
('c6343f7b-31fb-4951-831a-ec2a0f58dce5','感春四首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬里蒙塵六尺輿，一丸泥蠟十行書。',64,'全唐诗/poet.song.86000.json','["萬里蒙塵六尺輿，一丸泥蠟十行書。", "豫且往往窺魚服，屬國栖栖掘鼠餘。", "村徑紅稠花艷艷，沙平翠點樹疏疏。", "落霞孤鶩西南望，千頃洪波浸日車。"]'),
('0f596914-75bb-4867-9994-af94c43fe411','感春四首  其三','孫覿','宋','宋诗','song-poetry','','[]','村巷深深綠映人，粥餳槐火一時新。',64,'全唐诗/poet.song.86000.json','["村巷深深綠映人，粥餳槐火一時新。", "山河萬里纏妖氣，宮殿千門鎖暗塵。", "幾點微酸梅着子，半篙清漲水生鱗。", "巖花澗草元無主，雨洗風吹又一春。"]'),
('dda25adc-489b-47dc-9e3b-a7d717928157','感春四首  其四','孫覿','宋','宋诗','song-poetry','','[]','春物菲菲自解歡，雨鳴孤枕夜漫漫。',64,'全唐诗/poet.song.86000.json','["春物菲菲自解歡，雨鳴孤枕夜漫漫。", "忘形不到公榮飲，絕意休彈貢禹冠。", "離亂家書萬金直，艱難斗酒百憂寬。", "囊空甑倒誰能救，淚濕花枝不忍看。"]'),
('c6823465-6cf8-4a3b-a6bf-cda11c4b91b3','再用前韻四首  其一','孫覿','宋','宋诗','song-poetry','','[]','獵獵青旗傍酒家，映門楊柳受風斜。',64,'全唐诗/poet.song.86000.json','["獵獵青旗傍酒家，映門楊柳受風斜。", "行穿細路迷芳草，坐對空樽數落花。", "藜杖醉扶悲確犖，角巾欹倒露蒼華。", "故山渺莽愁眉外，翠竹青蒲繞白沙。"]'),
('7d45e113-31a5-4b2d-b1cd-f116e0b29ff8','再用前韻四首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬事破除惟有酒，半生勞苦坐看書。',64,'全唐诗/poet.song.86000.json','["萬事破除惟有酒，半生勞苦坐看書。", "青鞋雲水扁舟去，朱轂風塵一夢餘。", "戰格連雲胡騎滿，斷弦掛壁舊交疏。", "春泥活活朝天路，猶有和公擅一車。"]'),
('8af5b8c7-71e2-4ab7-9633-c0307350f6ca','再用前韻四首  其三','孫覿','宋','宋诗','song-poetry','','[]','亹亹交情青眼見，紛紛窮路白頭新。',64,'全唐诗/poet.song.86000.json','["亹亹交情青眼見，紛紛窮路白頭新。", "地偏壤斷門無轍，衣敝囊空甑有塵。", "但見荒村連虎穴，那知曳水暴龍鱗。", "誰人手挽天河去，一洗郊原浩蕩春。"]'),
('a06dacd8-8e3c-46bd-8c3a-ee6f18814f7b','再用前韻四首  其四','孫覿','宋','宋诗','song-poetry','','[]','胡塵慘慘纏林莽，海氣紛紛接淼漫。',64,'全唐诗/poet.song.86000.json','["胡塵慘慘纏林莽，海氣紛紛接淼漫。", "天上空傳脩月斧，人中那見切雲冠。", "干戈未解千憂結，杯酒相逢一笑寬。", "老眼逢春只思睡，花枝渾似霧中看。"]'),
('84712846-2d6a-40b0-870b-e89d008da761','新居城二首  其一','孫覿','宋','宋诗','song-poetry','','[]','戢戢盤蝸滿舍東，笑看蠻觸兩爭雄。',64,'全唐诗/poet.song.86000.json','["戢戢盤蝸滿舍東，笑看蠻觸兩爭雄。", "便攜龍具歸田去，更祝豚蹄望歲功。", "未怪席門多長者，肯教壑谷問吾公。", "超然獨到羲皇上，臥占南窗一枕風。"]'),
('7e29cf11-a255-494f-a753-0353dc45f36e','新居城二首  其二','孫覿','宋','宋诗','song-poetry','','[]','肝膽寥寥楚越分，鼻端不落郢人斤。',64,'全唐诗/poet.song.86000.json','["肝膽寥寥楚越分，鼻端不落郢人斤。", "倚門骯髒無如我，從客雍容孰似君。", "一榻方尊徐孺子，千篇不數鮑參軍。", "從今更欲論奇字，載酒重來問子雲。"]'),
('9ed645e6-f1bf-4dd5-8d1b-f3a7917fb33e','再贈彥明用前韻','孫覿','宋','宋诗','song-poetry','','[]','老幹輪囷不計春，強名居士愧詩人。',64,'全唐诗/poet.song.86000.json','["老幹輪囷不計春，強名居士愧詩人。", "共尊有若都非是，誤認顔標自有真。", "忽睹二豪聯白璧，坐令百鬼怖黄巾。", "它年若許陪蓮社，不惜千金剩買鄰。"]'),
('b02b217d-bbf0-49b3-9607-8af0a6b7eb53','送卓侍者二首  其一','孫覿','宋','宋诗','song-poetry','','[]','多病身如寄，長貧氣自華。',48,'全唐诗/poet.song.86000.json','["多病身如寄，長貧氣自華。", "只將窮事業，便當老生涯。", "泥飲醉生纈，挑燈喜見花。", "殷勤香火社，問病到毗耶。"]'),
('bf519123-d2f1-471d-98f8-d50c926337a8','送卓侍者二首  其二','孫覿','宋','宋诗','song-poetry','','[]','禪客青鞋軟，詩翁白帽斜。',48,'全唐诗/poet.song.86000.json','["禪客青鞋軟，詩翁白帽斜。", "驚飛蝶栩栩，喜見鵲查查。", "推戶風敲竹，登床雨散花。", "怱怱一笑許，隻履上青霞。"]'),
('920e3d98-e418-4559-811f-7172d3f22b1d','題吳生最樂軒','孫覿','宋','宋诗','song-poetry','','[]','曲徑通林樾，幽栖見草堂。',48,'全唐诗/poet.song.86000.json','["曲徑通林樾，幽栖見草堂。", "松雲春細細，山雨夜浪浪。", "逐臭如聞鮑，吹虀若探湯。", "平生爲善樂，應不羨濠梁。"]'),
('af6a4066-7375-4e4c-8462-592931e67ffa','和叔毅見寄二首  其一','孫覿','宋','宋诗','song-poetry','','[]','風塵蹭蹬悲游子，雞黍招邀愧老農。',64,'全唐诗/poet.song.86000.json','["風塵蹭蹬悲游子，雞黍招邀愧老農。", "盜取青氈無舊物，書憑黄耳有先容。", "乞憐不辨齊門掃，投老寧堪楚市舂。", "回首故山勞夢想，樓高百尺臥元龍。"]'),
('f0e2ae2e-d87a-4ba4-a6a0-c938615747f3','和叔毅見寄二首  其二','孫覿','宋','宋诗','song-poetry','','[]','莫遣聲名夸俗子，且將筋力伴耕農。',64,'全唐诗/poet.song.86000.json','["莫遣聲名夸俗子，且將筋力伴耕農。", "五湖魚鳥非先素，一塢山林肯見容。", "翠出短樊供小摘，香浮大甑飽新舂。", "鄰翁莫怪頻來集，門戶如今有八龍。"]'),
('f0e7e214-6f2f-4145-8e55-2e1a424d0acb','又和別韻','孫覿','宋','宋诗','song-poetry','','[]','歲陰袞袞驚心折，世事紛紛觸眼新。',64,'全唐诗/poet.song.86000.json','["歲陰袞袞驚心折，世事紛紛觸眼新。", "爍爍風燈深院雨，離離花草故城春。", "一區栽自無寧處，五斗誰能更爲貧。", "矢醉自醒還自笑，依稀卻是夢中真。"]'),
('83629c37-d03e-4ebc-b86c-dfda543e7df7','送天寧維老','孫覿','宋','宋诗','song-poetry','','[]','犀顱月面表千夫，吏用公才舉世無。',32,'全唐诗/poet.song.86000.json','["犀顱月面表千夫，吏用公才舉世無。", "鬬麗爭雄何足道，君看澄觀豈僧徒。"]'),
('9714827d-181b-488f-8d14-db81b6c7d0ab','鄒志新致書酒荔枝山栗海錯之餽四絕  其一','孫覿','宋','宋诗','song-poetry','','[]','門前剝啄響鳴騶，十里驚塵滿地地流。',33,'全唐诗/poet.song.86000.json','["門前剝啄響鳴騶，十里驚塵滿地地流。", "戀戀綈袍故人意，一書何啻萬金投。"]'),
('83c2600d-578e-45ee-a88d-de904b36c36c','鄒志新致書酒荔枝山栗海錯之餽四絕  其二','孫覿','宋','宋诗','song-poetry','','[]','窺簷雙鵲語匆匆，一夜燈花綴玉蟲。',32,'全唐诗/poet.song.86000.json','["窺簷雙鵲語匆匆，一夜燈花綴玉蟲。", "便有麴生來過我，盡推愁入酒杯中。"]'),
('bc312ea5-636d-4b55-87b6-a99b9ef344c4','鄒志新致書酒荔枝山栗海錯之餽四絕  其三','孫覿','宋','宋诗','song-poetry','','[]','白鴉谷口葉盤秋，荔子今無驛使求。',32,'全唐诗/poet.song.86000.json','["白鴉谷口葉盤秋，荔子今無驛使求。", "零落共誰一笑粲，殷勤爲報赤心投。"]'),
('4f237419-b126-4789-bcdb-273226c8d034','鄒志新致書酒荔枝山栗海錯之餽四絕  其四','孫覿','宋','宋诗','song-poetry','','[]','蠻珍不說紫駝峰，怪雨腥風起坐中。',32,'全唐诗/poet.song.86000.json','["蠻珍不說紫駝峰，怪雨腥風起坐中。", "莫遣蔡謨勤學死，須君爾雅注魚蟲。"]'),
('2f83d3ee-c683-4d66-bd65-457938884ca3','斗酒同小詩送楊君聖四絕  其一','孫覿','宋','宋诗','song-poetry','','[]','糟床灧灧玉虹流，洗盡胸中萬斛愁。',32,'全唐诗/poet.song.86000.json','["糟床灧灧玉虹流，洗盡胸中萬斛愁。", "待看百篇供太白，不將一斗換涼州。"]'),
('29333c90-f61c-44bd-9684-87984e6df962','斗酒同小詩送楊君聖四絕  其二','孫覿','宋','宋诗','song-poetry','','[]','天祿先生第一流，著書曾賦畔牢愁。',32,'全唐诗/poet.song.86000.json','["天祿先生第一流，著書曾賦畔牢愁。", "何人載酒論奇字，彷彿虞箴是九州。"]'),
('b669b71d-83ca-44e1-abcc-7ed9197fbb6e','斗酒同小詩送楊君聖四絕  其三','孫覿','宋','宋诗','song-poetry','','[]','習池尊俎擅風流，一洗干戈四海愁。',32,'全唐诗/poet.song.86000.json','["習池尊俎擅風流，一洗干戈四海愁。", "倒着接籬扶上馬，舉鞭一笑問幷州。"]'),
('4b01cf51-ca6b-40ab-884e-5b39908540d0','斗酒同小詩送楊君聖四絕  其四','孫覿','宋','宋诗','song-poetry','','[]','一水橫分醉眼流，兩峰遙蹙黛眉愁。',32,'全唐诗/poet.song.86000.json','["一水橫分醉眼流，兩峰遙蹙黛眉愁。", "醉眠千日中山酒，不羨三刀夢益州。"]'),
('4c441a5c-455a-4b7a-a4f2-90430f977747','簡彥廓求梅花二絕  其一','孫覿','宋','宋诗','song-poetry','','[]','畏寒春半尚跧藏，聞說江梅已弄芳。',32,'全唐诗/poet.song.86000.json','["畏寒春半尚跧藏，聞說江梅已弄芳。", "全樹不妨分一朵，夜窗時作定中香。"]'),
('62058aa7-76eb-4b59-9d7a-b7d70493a107','簡彥廓求梅花二絕  其二','孫覿','宋','宋诗','song-poetry','','[]','折來猶自带春寒，入手誰窮造化端。',32,'全唐诗/poet.song.86000.json','["折來猶自带春寒，入手誰窮造化端。", "鈿玉半含金蘸雪，嗅香須更細看看。"]'),
('0cd3a6a1-2392-42f1-8e50-d813b7f3ea0a','和公權梅花用前韻','孫覿','宋','宋诗','song-poetry','','[]','雪香瓊瘦逼人寒，閑澹精神畫亦難。',32,'全唐诗/poet.song.86000.json','["雪香瓊瘦逼人寒，閑澹精神畫亦難。", "照水可憐清更甚，不堪渾作鏡中看。"]'),
('38ef6a02-d692-43fd-9562-50febe5ddc7d','謝公惠梅花','孫覿','宋','宋诗','song-poetry','','[]','今年春晚懶尋芳，獨掩寒齋政坐忘。',32,'全唐诗/poet.song.86000.json','["今年春晚懶尋芳，獨掩寒齋政坐忘。", "多謝風流濠上掾，凌晨分我一枝春。"]'),
('31b73198-cfc9-408e-bc54-64bce17986c6','和落花流水四絕句依長文姪韻  其一','孫覿','宋','宋诗','song-poetry','','[]','雨花着地燕脂濕，風柳飄空帽絮披。',32,'全唐诗/poet.song.86000.json','["雨花着地燕脂濕，風柳飄空帽絮披。", "粉黛紛紛半黄土，蟹螯從此不須持。"]'),
('f69b2890-c7fd-4267-a22d-c12c85d4570c','和落花流水四絕句依長文姪韻  其二','孫覿','宋','宋诗','song-poetry','','[]','菌短椿長未易齊，雨花風葉任紛披。',32,'全唐诗/poet.song.86000.json','["菌短椿長未易齊，雨花風葉任紛披。", "甑盆已破誰能改，趺坐觀空且對持。"]'),
('40d89ee6-af3c-4eba-a77d-a5574967452f','和落花流水四絕句依長文姪韻  其三','孫覿','宋','宋诗','song-poetry','','[]','老怯風波一棹回，故園蕪沒半蒼苔。',32,'全唐诗/poet.song.86000.json','["老怯風波一棹回，故園蕪沒半蒼苔。", "水深莫遣蛟龍得，火急招歸海賈來。"]'),
('070128a9-f0e4-45cb-bf08-f785c3349e62','和落花流水四絕句依長文姪韻  其四','孫覿','宋','宋诗','song-poetry','','[]','淺淺微波照殘影，濺濺流潤細縈苔。',32,'全唐诗/poet.song.86000.json','["淺淺微波照殘影，濺濺流潤細縈苔。", "浮花浪蕊相隨去，鶯語丁寧挽不來。"]'),
('432ebf17-ecaa-4060-b405-7ee7d4ffdb9d','游惠山偶書','孫覿','宋','宋诗','song-poetry','','[]','春到梵王家，千林已着花。',24,'全唐诗/poet.song.86000.json','["春到梵王家，千林已着花。", "小桃無限思，竹外一枝斜。"]'),
('8035d1a2-2ddf-4f58-8123-a6e90dffcb71','主簿甥孫小舟載白菊一本見遺賦二小詩爲謝  其一','孫覿','宋','宋诗','song-poetry','','[]','飛瓊乘月下瑤臺，老眼驚窺一笑開。',32,'全唐诗/poet.song.86000.json','["飛瓊乘月下瑤臺，老眼驚窺一笑開。", "冰雪定嫌詩酒污，不應更待白衣來。"]'),
('afc5783c-306c-4aa5-9aef-9b010d96f975','主簿甥孫小舟載白菊一本見遺賦二小詩爲謝  其二','孫覿','宋','宋诗','song-poetry','','[]','水檻吹香風漸漸，月叢泛彩露團團。',32,'全唐诗/poet.song.86000.json','["水檻吹香風漸漸，月叢泛彩露團團。", "高情不入梨花夢，蝶亂蜂狂可得干。"]'),
('545afbae-9502-4a95-844c-fa937bd285ba','餞瑩上人','孫覿','宋','宋诗','song-poetry','','[]','金地布時黄鶴下，化身現處赤烏來。',32,'全唐诗/poet.song.86000.json','["金地布時黄鶴下，化身現處赤烏來。", "如今隻履西歸去，又見天花一葉開。"]'),
('da8bd658-ad1c-430d-85e6-2b20d7b90460','張子爲園林八詠 別芳','孫覿','宋','宋诗','song-poetry','','[]','縹带湘枝半欹牆，行人立馬幷垂楊。',32,'全唐诗/poet.song.86000.json','["縹带湘枝半欹牆，行人立馬幷垂楊。", "珠簾半捲揚州路，爭看金釵十二行。"]'),
('ff4b63e4-4671-44d6-9b55-cbd607a8d503','張子爲園林八詠 友花','孫覿','宋','宋诗','song-poetry','','[]','午枕驚回一夢餘，間關枝上聽催酤。',32,'全唐诗/poet.song.86000.json','["午枕驚回一夢餘，間關枝上聽催酤。", "已招十客花爲友，更覓千頭橘作奴。"]'),
('67cd90b7-3425-4e07-9a9b-c395f252789b','張子爲園林八詠 照艷','孫覿','宋','宋诗','song-poetry','','[]','摶雲琢雪鬬輕盈，一片霞光夜自明。',32,'全唐诗/poet.song.86000.json','["摶雲琢雪鬬輕盈，一片霞光夜自明。", "會有國香來入夢，莫教高燭照長檠。"]'),
('34001619-2bcf-47cb-a7e6-adf7680edc42','張子爲園林八詠 浮香','孫覿','宋','宋诗','song-poetry','','[]','冰姿更立冰谿上，雪艷仍開雪徑中。',32,'全唐诗/poet.song.86000.json','["冰姿更立冰谿上，雪艷仍開雪徑中。", "白地迷藏不知處，云何鼻觀已先通。"]'),
('67540f98-3a15-42c2-b99f-0b7b6e65de9a','張子爲園林八詠 水香','孫覿','宋','宋诗','song-poetry','','[]','半篙新漲淥周遭，種出荷花十丈高。',32,'全唐诗/poet.song.86000.json','["半篙新漲淥周遭，種出荷花十丈高。", "擷秀堪紉水仙佩，招詞更續楚臣騷。"]'),
('c7a83752-dbf8-4524-ad95-fbc0f98629e0','張子爲園林八詠 小蓮','孫覿','宋','宋诗','song-poetry','','[]','蓮渚紅酣三丈日，苔磯輕颺一絲風。',32,'全唐诗/poet.song.86000.json','["蓮渚紅酣三丈日，苔磯輕颺一絲風。", "釣船篷底眠秋雨，誰遣南柯入夢中。"]'),
('90e82025-166e-4b2f-a00a-722a5f451dd9','張子爲園林八詠 蒲桃徑','孫覿','宋','宋诗','song-poetry','','[]','手植蓬藤數千尋，笑看潘液上駸駸。',32,'全唐诗/poet.song.86000.json','["手植蓬藤數千尋，笑看潘液上駸駸。", "使君千騎東方去，零落空留一院陰。"]'),
('efeacc0b-1795-42ec-9efd-c59c27d34e1a','張子爲園林八詠 曲塘','孫覿','宋','宋诗','song-poetry','','[]','一曲清深五月寒，不知中有老蛟蟠。',32,'全唐诗/poet.song.86000.json','["一曲清深五月寒，不知中有老蛟蟠。", "雷撾半夜驚飛去，已見天南九萬摶。"]'),
('b3b0c836-8b89-4ef2-b153-a716a5a95934','巴東使君王夢得挽詞','孫覿','宋','宋诗','song-poetry','','[]','谷口聲名動帝庭，芝塗一札下西清。',64,'全唐诗/poet.song.86000.json','["谷口聲名動帝庭，芝塗一札下西清。", "安車倍道徵杖叔，前席通宵問賈生。", "俊辯瀾翻驚辟易，長身玉立看崢嶸。", "飄然比夕騎箕去，那見麒麟地上行。"]'),
('fb84a61f-701c-4872-9130-e0f92abb3da9','樞密周府君挽詞','孫覿','宋','宋诗','song-poetry','','[]','少日聲名冠兩科，弁星爭看切雲峨。',96,'全唐诗/poet.song.86000.json','["少日聲名冠兩科，弁星爭看切雲峨。", "回翔禁路聯三組，獨步樞庭擁萬戈。", "飲馬直須臨瀚海，洗兵端欲挽天河。", "壯懷落落今休矣，急景駸駸可奈何。", "蟻動忽聽牀下鬬，駒跳已向隙中過。", "泉原一閉成千古，有客哀吟只浩歌。"]'),
('03140054-caec-4ed5-9f6a-da31a83a6ecf','信安郡夫人挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','蟬聯女公子，湯沐郡夫人。',48,'全唐诗/poet.song.86000.json','["蟬聯女公子，湯沐郡夫人。", "籍著金閨密，綸褒袞字新。", "千葩朝閬苑，雙劍化平津。", "唧唧蟲吟夜，梁空落暗塵。"]'),
('0fc20b21-f8ff-41aa-bb36-650fc2e3e425','信安郡夫人挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','夫擁侍臣櫜，兒乘刺史軺。',48,'全唐诗/poet.song.86000.json','["夫擁侍臣櫜，兒乘刺史軺。", "澗蘋借采采，風棘盛夭夭。", "尚想萊班戲，空留楚挽招。", "魌頭引丹旐，千古閟山椒。"]'),
('2a088a2f-79e2-4840-8519-2ac0bdc54a61','致政沈通直挽詞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','門大聯三虎，途窮曳九牛。',48,'全唐诗/poet.song.86000.json','["門大聯三虎，途窮曳九牛。", "一官投紱去，萬事蓋棺休。", "寂寂蘭亭月，寥寥蕙帳秋。", "羊曇他日淚，慟哭過西州。"]'),
('eaac4a3e-70e1-4d5c-a866-3e5507cd65a4','致政沈通直挽詞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','小隱疏三徑，浮榮寓一漚。',48,'全唐诗/poet.song.86000.json','["小隱疏三徑，浮榮寓一漚。", "歲陰駒隙過，文采豹皮留。", "不踏邯鄲道，聊追汗漫游。", "菟裘應好在，千載寄風流。"]'),
('4d9bc22b-e3c4-4436-82cb-623f4c1a0c10','和州餞交代趙朝議樂語','孫覿','宋','宋诗','song-poetry','','[]','天涯萬里一尊同，醉眼愁看月墮空。',64,'全唐诗/poet.song.86000.json','["天涯萬里一尊同，醉眼愁看月墮空。", "畫角孤吹千嶂曉，綵舟橫曳半江紅。", "啼妝盡带梨花雨，舞袖猶翻柳絮風。", "只有邦人頌遺愛，棠陰繞屋自蘢葱。"]'),
('c4a61d2d-638e-41ec-af3c-e037e969f334','平江燕張節使樂語','孫覿','宋','宋诗','song-poetry','','[]','秋風獵獵卷法旌，賊壘怱怱唾手平。',64,'全唐诗/poet.song.86000.json','["秋風獵獵卷法旌，賊壘怱怱唾手平。", "笑倚柁樓天上坐，臥聞鼓角地中聲。", "九門合遝追鋒去，千里讙呼負弩迎。", "從此三吳傳勝事，一時草木盡知名。"]'),
('3f5150e7-1f20-4bab-9c1c-3eb6e093d066','題瑯邪亭','孫覿','宋','宋诗','song-poetry','','[]','十里雲煙山繞郭，一川風雨樹參天。',64,'全唐诗/poet.song.86000.json','["十里雲煙山繞郭，一川風雨樹參天。", "漸看綠筍穿林出，已見新荷弄水圓。", "逐客詎堪分竹使，疲氓正合用蒲鞭。", "郡僚若得岑公孝，便欲燒香閉閤眠。"]'),
('8e6acd77-3454-4bf9-b64a-acf098eecae1','王相生辰  其一','孫覿','宋','宋诗','song-poetry','','[]','了了三生夢，松根冷鍛爐。',72,'全唐诗/poet.song.86000.json','["了了三生夢，松根冷鍛爐。", "四山朝鶴駕，五老奉龜圖。", "萱殿披敷策，星躔煥六符。", "玉笙歌綵鳳，革履墮飛鳬。", "命世千齡合，承天一柱扶。", "堂堂白虎殿，卻走漢單于。"]'),
('786d1aa9-f061-48c8-998a-338d50413390','王相生辰  其二','孫覿','宋','宋诗','song-poetry','','[]','審象膺商卜，占熊協渭祥。',72,'全唐诗/poet.song.86000.json','["審象膺商卜，占熊協渭祥。", "金湯蟠萬里，杞梓蔭千章。", "獨斡堪輿大，垂鴻带礪長。", "解絃參虎變，調燭驗金穰。", "鼎重開周曆，巖瞻拱舜裳。", "太平如有象，儀鳳舞蹌蹌。"]'),
('7ba02fbc-e712-417e-8c2e-55bc2c45dba8','致政朝奉挽詞  其一','孫覿','宋','宋诗','song-poetry','','[]','出岫孤雲自卷舒，平生心事付樵漁。',64,'全唐诗/poet.song.86000.json','["出岫孤雲自卷舒，平生心事付樵漁。", "便抽手板還丞相，獨把鴟夷載後車。", "掃軌更無雲外轍，傳家尚有枕中書。", "百年大夢行當覺，日月渾將一醉除。"]'),
('f9fe24b3-b4d8-483a-904c-377293f8caa9','致政朝奉挽詞  其二','孫覿','宋','宋诗','song-poetry','','[]','床頭蟻鬬兩牛鳴，起起誰呼寢夢驚。',64,'全唐诗/poet.song.86000.json','["床頭蟻鬬兩牛鳴，起起誰呼寢夢驚。", "不用沉文招九死，曾因叩角悟三生。", "取氈臥看偷兒入，折券羞同賈竪爭。", "天定勝人端可必，坐看驥子籋雲行。"]'),
('4d93cf0a-d8ab-49ec-9712-e15643d009bc','虎丘','孫覿','宋','宋诗','song-poetry','','[]','冬溫陽久亢，一雪意頗快。',96,'全唐诗/poet.song.86000.json','["冬溫陽久亢，一雪意頗快。", "乘興泛扁舟，出郭信如邁。", "放棹得虎丘，恍然銀色界。", "瑤山夾細徑，瓊樹偃曲蓋。", "引步到層樓，極目吳城隘。", "飛鸞翔空中，千峰冪天外。", "暗虛雲可凌，寒重酒易解。", "羣兒慶老翁，于此氣不憊。"]'),
('aea79164-b55f-44f9-94d7-49c720ac3ff8','帝城上巳','孫覿','宋','宋诗','song-poetry','','[]','宿霧消神沼，晴曦照碧峰。',96,'全唐诗/poet.song.86000.json','["宿霧消神沼，晴曦照碧峰。", "祓除周故事，環宴楚遺風。", "畫舸低搖鶂，浮梁冷亘虹。", "五陵驅羣少，三殿錫鷁公。", "浪射簪纓潤，花迎劍佩紅。", "舞遲歌袂穩，飛急酒觴空。", "淑氣琱軒外，祥光禁籞中。", "敢賡元首詠，上記帝堯功。"]'),
('f5620aa9-3133-47c0-95f6-ad9e8f461fde','端午日帖子詞 皇帝閤六首 其一','孫覿','宋','宋诗','song-poetry','','[]','薰琴應律南風暖，漏箭添籌晝刻長。',32,'全唐诗/poet.song.86000.json','["薰琴應律南風暖，漏箭添籌晝刻長。", "誰識廣寒天上景，銅烏未午送微涼。"]'),
('f813fccf-f776-482d-8f79-355b5d1b8221','端午日帖子詞 皇帝閤六首 其二','孫覿','宋','宋诗','song-poetry','','[]','炎日曈曈照殿楹，幅員萬里塞氛清。',32,'全唐诗/poet.song.86000.json','["炎日曈曈照殿楹，幅員萬里塞氛清。", "漢家自有安邊術，不是靈符解辟兵。"]'),
('7da81655-0740-40f3-8586-734d28cee3d4','端午日帖子詞 皇帝閤六首 其三','孫覿','宋','宋诗','song-poetry','','[]','方更仲律清和節，正是南訛化育時。',31,'全唐诗/poet.song.86000.json','["方更仲律清和節，正是南訛化育時。", "無限元元齊歌舞，恤刑新詔下墀。"]'),
('607df8a7-afc8-4f58-898e-02991213c66b','端午日帖子詞 皇帝閤六首 其四','孫覿','宋','宋诗','song-poetry','','[]','露畹擷蘭苕，金波麗碧霄。',24,'全唐诗/poet.song.86000.json','["露畹擷蘭苕，金波麗碧霄。", "早聞彫輦降，還待紫宸朝。"]'),
('e9eab466-afb5-4563-8e2e-669761892e80','端午日帖子詞 皇帝閤六首 其五','孫覿','宋','宋诗','song-poetry','','[]','內苑屬嘉辰，初收百藥新。',24,'全唐诗/poet.song.86000.json','["內苑屬嘉辰，初收百藥新。", "預知氛癘息，天意在生民。"]'),
('248ee412-ea31-436c-a3b5-8ebd0c506564','端午日帖子詞 皇帝閤六首 其六','孫覿','宋','宋诗','song-poetry','','[]','淺囿含桃老，雕盤角黍香。',24,'全唐诗/poet.song.86000.json','["淺囿含桃老，雕盤角黍香。", "九重端扆處，星火正離方。"]'),
('d5e93ac8-7075-4cf4-a70f-e541d0103543','端午日帖子詞 皇后閤五首 其一','孫覿','宋','宋诗','song-poetry','','[]','蟠桃映砌晨煙薄，紫桂凌霄晝露晞。',32,'全唐诗/poet.song.86000.json','["蟠桃映砌晨煙薄，紫桂凌霄晝露晞。", "窈窕漢宮三十六，齊將綵縷祝坤闈。"]'),
('1cc3805b-9d02-46e0-a93c-8d2ea7627785','端午日帖子詞 皇后閤五首 其二','孫覿','宋','宋诗','song-poetry','','[]','暑服初頒五柞宮，內墀佳氣鬰葱葱。',32,'全唐诗/poet.song.86000.json','["暑服初頒五柞宮，內墀佳氣鬰葱葱。", "須知海宇昇平事，半是關雎輔佐功。"]'),
('083d7486-4356-4ce6-8a6c-1d9506b314b6','端午日帖子詞 皇后閤五首 其三','孫覿','宋','宋诗','song-poetry','','[]','方均寶笈千齡藥，又賜金盤五色瓜。',32,'全唐诗/poet.song.86000.json','["方均寶笈千齡藥，又賜金盤五色瓜。", "從此仙源深福遠，綿綿不獨頌周家。"]'),
('3688a2bc-18c6-4d07-8bf8-39e131aa76df','端午日帖子詞 皇后閤五首 其四','孫覿','宋','宋诗','song-poetry','','[]','浴蘭同故事，戲草楚遺風。',24,'全唐诗/poet.song.86000.json','["浴蘭同故事，戲草楚遺風。", "不是天家意，勤勞念女紅。"]'),
('0db40aeb-a70b-46b8-b664-f32fe407053b','端午日帖子詞 皇后閤五首 其五','孫覿','宋','宋诗','song-poetry','','[]','洞戶花陰淺，天階日景遲。',24,'全唐诗/poet.song.86000.json','["洞戶花陰淺，天階日景遲。", "糉成八九子，縷結就千絲。"]'),
('1604f9ce-a3f6-4b1b-9e45-52daf7cadb7e','端午日帖子詞 夫人閤五首 其一','孫覿','宋','宋诗','song-poetry','','[]','杳杳畫梁巍架杏，沉沉香壁靜塗椒。',32,'全唐诗/poet.song.86000.json','["杳杳畫梁巍架杏，沉沉香壁靜塗椒。", "宮前夜祝君王壽，日上黄爐炷未消。"]'),
('8d73b1b6-3a76-46a9-b14f-ecd55eea3120','端午日帖子詞 夫人閤五首 其二','孫覿','宋','宋诗','song-poetry','','[]','交飛壽斝長生殿，競泛仙舟太液池。',32,'全唐诗/poet.song.86000.json','["交飛壽斝長生殿，競泛仙舟太液池。", "不似世間多暑氣，天風淅淅萬年枝。"]'),
('394712ce-96a9-4375-82c4-51e0ee7e4474','端午日帖子詞 夫人閤五首 其三','孫覿','宋','宋诗','song-poetry','','[]','辟惡何須荆楚艾，蠲炎不待邵平瓜。',32,'全唐诗/poet.song.86000.json','["辟惡何須荆楚艾，蠲炎不待邵平瓜。", "仙飈昨夜來閶闔，玉宇清涼大帝家。"]'),
('b8655d0e-6127-4bb0-91ba-bdbf1ec0558f','端午日帖子詞 夫人閤五首 其四','孫覿','宋','宋诗','song-poetry','','[]','畫閣方裁扇，寒塘又鑿冰。',24,'全唐诗/poet.song.86000.json','["畫閣方裁扇，寒塘又鑿冰。", "蓬壺山四徹，何處是炎蒸。"]'),
('eb0fe21a-bccb-4e00-9c80-2bf5080a3e2f','端午日帖子詞 夫人閤五首 其五','孫覿','宋','宋诗','song-poetry','','[]','仙宇賜符時，仙蓂葉尚稀。',24,'全唐诗/poet.song.86000.json','["仙宇賜符時，仙蓂葉尚稀。", "曉來金屋靜，同侍玉皇歸。"]'),
('0cd2488f-d423-4484-9f56-b62986b89668','過沈仲嘉園亭題贈','孫覿','宋','宋诗','song-poetry','','[]','包山美人構亭子，巋然屹立深園裏。',96,'全唐诗/poet.song.86000.json','["包山美人構亭子，巋然屹立深園裏。", "窗近斷巖見怪石，壁臨絕磵聞流水。", "亭中一架古人書，知是羣經及諸史。", "桐葉滴露下陰砌，橘花隨風飄靜几。", "美人素厭世俗語，有語利名須洗耳。", "衡門反關高枕眠，紅日三竿猶未起。"]'),
('9619b4a6-98ba-4129-aa87-b251c6b56498','贈善慶堂主人夏元富','孫覿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','居士藏修洞庭野，新架虛堂殊瀟灑。',112,'全唐诗/poet.song.86000.json','["居士藏修洞庭野，新架虛堂殊瀟灑。", "閑門開傍橘柚林，萬顆千株映青赭。", "居士優游每不出，左列圖書右盞斚。", "逢迎自覺青眼衆，來往應知白丁寡。", "莓苔經雨上石砌，蘿薜迎風拂簷瓦。", "素聞平生剩積善，餘慶當傳累世下。", "醉揮健筆賦新詩，輒贈堂中樂居者。"]'),
('396f0775-ba03-48fb-977f-16fe35d29012','句','孫覿','宋','宋诗','song-poetry','','[]','噬臍有愧平燕日，嘗膽無忘在莒時。',16,'全唐诗/poet.song.86000.json','["噬臍有愧平燕日，嘗膽無忘在莒時。"]'),
('42e6af3f-e929-4289-b2e8-2c9b01fdeaa2','艮嶽百詠 艮嶽','李質','宋','宋诗','song-poetry','','[]','勢連坤軸近乾岡，地首東維鎮八方。',32,'全唐诗/poet.song.86000.json','["勢連坤軸近乾岡，地首東維鎮八方。", "江不風波山不險，子孫千億壽無疆。"]'),
('47a17b8c-68e3-4507-8d0b-fdf759f8c711','艮嶽百詠 介亭','李質','宋','宋诗','song-poetry','','[]','雲棧橫空入翠煙，躋攀端可躡飛仙。',32,'全唐诗/poet.song.86000.json','["雲棧橫空入翠煙，躋攀端可躡飛仙。", "介然獨出諸山上，磊磊排衙石滿前。"]'),
('5f2d0ef3-3522-4528-84fe-131a98f94a10','艮嶽百詠 極目亭','李質','宋','宋诗','song-poetry','','[]','千里飛鴻坐上看，山川風月在憑欄。',32,'全唐诗/poet.song.86000.json','["千里飛鴻坐上看，山川風月在憑欄。", "不知地占最高處，但覺恢恢天宇寛。"]'),
('b9deee04-a049-445a-89c9-cbf41eb50cbb','艮嶽百詠 圌山亭','李質','宋','宋诗','song-poetry','','[]','軒楹正在翠微中，欲雪雲生四面峰。',32,'全唐诗/poet.song.86000.json','["軒楹正在翠微中，欲雪雲生四面峰。", "璀璨地鋪紅瑪瑙，巑岏山聳碧芙蓉。"]'),
('9687f662-c271-40ad-9dd3-2ef54c06c37a','艮嶽百詠 跨雲亭','李質','宋','宋诗','song-poetry','','[]','地高天近怯憑欄，下視浮雲咫尺間。',32,'全唐诗/poet.song.86000.json','["地高天近怯憑欄，下視浮雲咫尺間。", "只怪輕雷起巖際，不知飛雨過前山。"]'),
('090d94b2-651f-4672-8451-11d89772a76b','艮嶽百詠 半山亭','李質','宋','宋诗','song-poetry','','[]','憑高玉輦每從容，中路嘗聞憩六龍。',32,'全唐诗/poet.song.86000.json','["憑高玉輦每從容，中路嘗聞憩六龍。", "塵外有人如到此，便須行徹最高峰。"]'),
('97773c9a-07e5-433b-b6bd-cde5e70410aa','艮嶽百詠 蕭森亭','李質','宋','宋诗','song-poetry','','[]','曉日玲瓏宿霧開，四簷時有好風來。',32,'全唐诗/poet.song.86000.json','["曉日玲瓏宿霧開，四簷時有好風來。", "不應班竹林中見，却似松根琥珀堆。"]'),
('30b18a92-912c-4f0d-8f41-7b1ef2522f24','艮嶽百詠 麓雲亭','李質','宋','宋诗','song-poetry','','[]','山下深林起白雲，白雲飛處斷紅塵。',32,'全唐诗/poet.song.86000.json','["山下深林起白雲，白雲飛處斷紅塵。", "伴行直到高峰上，舒卷縱橫不礙人。"]'),
('1939681c-00a0-430b-8899-8f87223f3685','艮嶽百詠 清賦亭','李質','宋','宋诗','song-poetry','','[]','四海熙熙萬物和，太平廊廟只賡歌。',32,'全唐诗/poet.song.86000.json','["四海熙熙萬物和，太平廊廟只賡歌。", "欲追林下騷人意，却是臨流得句多。"]'),
('6554f4a4-6a8b-4fbd-ac96-6180b722782a','艮嶽百詠 散綺亭','李質','宋','宋诗','song-poetry','','[]','斷虹飛雨過天涯，碧落浮雲不復遮。',32,'全唐诗/poet.song.86000.json','["斷虹飛雨過天涯，碧落浮雲不復遮。", "明日陰晴真可卜，倚欄來此看餘霞。"]'),
('5e1c93af-9ad7-4b2c-beb9-3205fb916972','艮嶽百詠 清斯亭','李質','宋','宋诗','song-poetry','','[]','天波萬斛瀉鎔銀，跨水橫橋麗構新。',32,'全唐诗/poet.song.86000.json','["天波萬斛瀉鎔銀，跨水橫橋麗構新。", "但取真堪濯纓意，玉階金闕本無塵。"]'),
