('b0c6f0a9-f4c9-44ac-b65f-26aaad25428d','句','謝泂','宋','宋诗','song-poetry','','[]','溪瘦玉聲小，山橫翠色深。',12,'全唐诗/poet.song.86000.json','["溪瘦玉聲小，山橫翠色深。"]'),
('4d555b19-9641-4180-9e34-ed2a32a1d3dc','送童宣撫平燕班師','詹度','宋','宋诗','song-poetry','','[]','長亭春色送英雄，滿目江山映日紅。',64,'全唐诗/poet.song.86000.json','["長亭春色送英雄，滿目江山映日紅。", "劍戟夜搖楊柳月，旌旗曉拂杏花風。", "行時一決平戎策，到後須成濟世功。", "爲報燕山諸將吏，太平取在笑談中。"]'),
('25c25ff1-8b31-44cf-986f-008fc3ccde4b','讀翠微集','蓋嶼','宋','宋诗','song-poetry','','[]','聖宋吟哦只九僧，詩成往往比陽春。',32,'全唐诗/poet.song.86000.json','["聖宋吟哦只九僧，詩成往往比陽春。", "翠微閣上今朝見，格老辭清又一人。"]'),
('ad993568-9835-4b3f-82f5-4ecae4f1e52e','奉同程致道著作次鮑溶冬夜答客韻送趙叔問奉議歸南都','方元修','宋','宋诗','song-poetry','','[]','清秋不相借，白髮日更多。',96,'全唐诗/poet.song.86000.json','["清秋不相借，白髮日更多。", "塵埃困煩促，原野懷經過。", "聊當倚滂潤，資以生吾禾。", "豈不念離羣，驚鵲寧擇窼。", "王孫別都去，澹若依松蘿。", "暫別亦復難，賡詩飲無何。", "我行那爾爾，渺邈踰江河。", "賸須作佳句，相我滄浪歌。"]'),
('8af2b594-76c2-45b2-a056-c242d679c8e7','正月七日初見梅花','方元修','宋','宋诗','song-poetry','','[]','雪凈冰融溪作鱗，梅花經眼日當人。',64,'全唐诗/poet.song.86000.json','["雪凈冰融溪作鱗，梅花經眼日當人。", "北枝風力顧不早，東閣詩情聊一新。", "煙並博山薫莫亂，色同衰鬢插宜新。", "一年好處得全盡，紅綻雨肥猶弄春。"]'),
('2d678496-2026-4941-84df-95dd758a496e','句','楊信祖','宋','宋诗','song-poetry','','[]','共約城南方。',6,'全唐诗/poet.song.86000.json','["共約城南方。"]'),
('608d2e2d-d200-4873-8da6-8702874f8e7d','白龜泉','皇甫渙','宋','宋诗','song-poetry','','[]','靈臺塵不止，塵止非靈臺。',24,'全唐诗/poet.song.86000.json','["靈臺塵不止，塵止非靈臺。", "愛此一泓水，曾棲靈物來。"]'),
('f702e89b-0297-4467-bade-a68c865c365e','偈','釋文準弟子','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282", "\u4eba\u751f", "\u611f\u53f9"]','寒食因悲郭外春，野田無處不傷神。',32,'全唐诗/poet.song.86000.json','["寒食因悲郭外春，野田無處不傷神。", "林間纍纍添新塚，半是去年來哭人。"]'),
('840eb8d4-b332-4779-a886-f94a8085e445','宿禪房院','程祁','宋','宋诗','song-poetry','','[]','山庵極迴互，禪房深晦藏。',48,'全唐诗/poet.song.86000.json','["山庵極迴互，禪房深晦藏。", "紅塵來不到，虛室自生涼。", "好鳥時孤囀，幽蘭靜亦香。", "征車又曉去，終恨世緣長。"]'),
('bca3a075-d87f-4417-9a52-54c8e979b61c','再宿禪房院五首  其一','程祁','宋','宋诗','song-poetry','','[]','作意尋蘭若，重來是有緣。',48,'全唐诗/poet.song.86000.json','["作意尋蘭若，重來是有緣。", "眼前真是喜，境熟故依然。", "歸迹休論靜，收心莫話禪。", "廊虛剩看月，照影枕書眠。"]'),
('321a6829-8401-4af6-84d5-6de1dbf8797a','再宿禪房院五首  其二','程祁','宋','宋诗','song-poetry','','[]','暫屏喧囂想，來尋斷續香。',48,'全唐诗/poet.song.86000.json','["暫屏喧囂想，來尋斷續香。", "微風吹客袂，孤月照禪房。", "靜起勞生念，閑諳養性方。", "欹眠不成夢，夜久轉清涼。"]'),
('434af362-96ee-48dd-84a2-cfc7350b9796','再宿禪房院五首  其三','程祁','宋','宋诗','song-poetry','','[]','春蘭與秋菊，各是一時花。',48,'全唐诗/poet.song.86000.json','["春蘭與秋菊，各是一時花。", "芳馥聊應爾，淹留定自佳。", "客塵隨處有，歸夢計程賒。", "采采眼前物，令人惜歲華。"]'),
('bbe3daa8-e824-498f-b68b-b44efdd6a4ec','再宿禪房院五首  其四','程祁','宋','宋诗','song-poetry','','[]','策策日乾禾，蕭蕭風晚木。',48,'全唐诗/poet.song.86000.json','["策策日乾禾，蕭蕭風晚木。", "秋容全未老，歲事十分熟。", "寺古斷行跡，林幽聊稅足。", "遙聞擊壤響，知是先年曲。"]'),
('03182273-80a8-4518-97dd-f3cd6d87849d','再宿禪房院五首  其五','程祁','宋','宋诗','song-poetry','','[]','獻計憂不售，逃形惟願深。',48,'全唐诗/poet.song.86000.json','["獻計憂不售，逃形惟願深。", "老來銷外念，閑處愜幽尋。", "晚草媚遲景，殘蟬噪暝林。", "欲將詩遣興，誰解此時心。"]'),
('c0cc0b7b-c866-428b-916c-0d1054badc7c','輓三靈山人','程祁','宋','宋诗','song-poetry','','[]','昔讀先生傳，埋銘屬鄙文。',48,'全唐诗/poet.song.86000.json','["昔讀先生傳，埋銘屬鄙文。", "里門經歲別，人事一朝分。", "宿諾成虛語，遺言忍重聞。", "傷心吟楚些，知我不欺君。"]'),
('b05fa309-ca63-43a9-8a45-6586c67446b8','宴集','程祁','宋','宋诗','song-poetry','','[]','九老當年樂有餘，於今五老更歡娛。',32,'全唐诗/poet.song.86000.json','["九老當年樂有餘，於今五老更歡娛。", "喬松百尺倚天外，也許蒿萊入畫圖。"]'),
('609fc2e5-0850-4da3-a96c-e604b2c3c6ea','宮詞  其一','宋徽宗','宋','宋诗','song-poetry','','[]','塗丹輝映霽煙明，四啟嚴聞曉漏清。',32,'全唐诗/poet.song.86000.json','["塗丹輝映霽煙明，四啟嚴聞曉漏清。", "初御廣庭人意肅，九宮遙聽警鞭聲。"]'),
('f26f0897-38df-44a4-acf8-9784e4508a82','宮詞  其二','宋徽宗','宋','宋诗','song-poetry','','[]','御溝春水綠濺濺，曲沼迴波四接連。',32,'全唐诗/poet.song.86000.json','["御溝春水綠濺濺，曲沼迴波四接連。", "環碧下臨方鑑靜，遊魚跳躍浪痕圓。"]'),
('5535d4df-a4bc-4572-b29f-9abcf1417df0','宮詞  其三','宋徽宗','宋','宋诗','song-poetry','','[]','春朝小雨乍新晴，祥靄匀收洞宇明。',32,'全唐诗/poet.song.86000.json','["春朝小雨乍新晴，祥靄匀收洞宇明。", "嚴警不聞人一語，海棠枝上曉鶯聲。"]'),
('90c184f6-0cd1-468d-a87f-98ae16712229','宮詞  其四','宋徽宗','宋','宋诗','song-poetry','','[]','宮嬪餘樂稱幽閑，不喜濃糚鬬媚顔。',32,'全唐诗/poet.song.86000.json','["宮嬪餘樂稱幽閑，不喜濃糚鬬媚顔。", "浣罷竹風蠲濁慮，一輪明月照屏山。"]'),
('e0f6266c-dc0b-4c4f-82ec-bf4a10d5f7eb','宮詞  其五','宋徽宗','宋','宋诗','song-poetry','','[]','宣和庭廡四廻環，書畫金籯兩掖間。',32,'全唐诗/poet.song.86000.json','["宣和庭廡四廻環，書畫金籯兩掖間。", "韜袐緘扃飛寶構，鼎新文供稱幽閑。"]'),
('4bd39351-5d59-4622-86f2-94e05c7437e1','宮詞  其六','宋徽宗','宋','宋诗','song-poetry','','[]','春工先與上林芳，迎歲紅梅破臘香。',32,'全唐诗/poet.song.86000.json','["春工先與上林芳，迎歲紅梅破臘香。", "才過閣門分曲檻，弄晴繁蘂麗如糚。"]'),
('bce331d3-e1b0-4bdd-86b9-82ceb74b96ec','宮詞  其七','宋徽宗','宋','宋诗','song-poetry','','[]','玉宇珍庭夜未央，月移花影上廻廊。',32,'全唐诗/poet.song.86000.json','["玉宇珍庭夜未央，月移花影上廻廊。", "精神勤禱祗民福，耿耿晴空靄露香。"]'),
('b550e131-63ee-48b4-b646-ed121c85a6a6','宮詞  其八','宋徽宗','宋','宋诗','song-poetry','','[]','羲獻真蹤勝古初，摉求方得到皇居。',32,'全唐诗/poet.song.86000.json','["羲獻真蹤勝古初，摉求方得到皇居。", "退朝彛鼎然沈水，因染霜毫更學書。"]'),
('8686a52d-7089-4b1d-b590-1da34a27e97f','宮詞  其九','宋徽宗','宋','宋诗','song-poetry','','[]','嘉禾呈瑞已爲殊，更有靈芝拱翠趺。',32,'全唐诗/poet.song.86000.json','["嘉禾呈瑞已爲殊，更有靈芝拱翠趺。", "通進剡章知異物，飜傳繪畫作新圖。"]'),
('aac957c3-16f4-4c8f-b01f-ae1f3523856b','宮詞  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','麟隄千尺盡塗丹，文瓦雕甍敞殿寛。',32,'全唐诗/poet.song.86000.json','["麟隄千尺盡塗丹，文瓦雕甍敞殿寛。", "折檻盡循前古制，當中一曲不安欄。"]'),
('8e514537-f23e-4781-9e38-1b0a754e6c4a','宮詞  其一一','宋徽宗','宋','宋诗','song-poetry','','[]','雲臺呈瑞出坤珍，龍角層芝玉色新。',32,'全唐诗/poet.song.86000.json','["雲臺呈瑞出坤珍，龍角層芝玉色新。", "從此九莖何足尚，圖書麟閣永無倫。"]'),
('847e6057-3d48-44fb-bf36-4a06e3bae1c5','宮詞  其一二','宋徽宗','宋','宋诗','song-poetry','','[]','秦娥從小學宮韶，竊愛仙音韻逸飄。',32,'全唐诗/poet.song.86000.json','["秦娥從小學宮韶，竊愛仙音韻逸飄。", "應慕鳳臺吹紫玉，夜闌時按白牙簫。"]'),
('4b86f045-8954-495f-8fc3-655e6fe11435','宮詞  其一三','宋徽宗','宋','宋诗','song-poetry','','[]','元宵三五競芳年，十二都門沸管絃。',32,'全唐诗/poet.song.86000.json','["元宵三五競芳年，十二都門沸管絃。", "鼇負繒山輝絳闕，龍銜寶炬撒金蓮。"]'),
('703b8dfb-d4b9-4c62-a334-ea3a199382d2','宮詞  其一四','宋徽宗','宋','宋诗','song-poetry','','[]','拂隄絲柳弄春柔，盈沼沉波瑩鴨頭。',32,'全唐诗/poet.song.86000.json','["拂隄絲柳弄春柔，盈沼沉波瑩鴨頭。", "錦繡成叢飛畫檝，輕舠兩兩翼龍舟。"]'),
('8e382aaf-bd6e-48e0-88ed-f1a67fc03264','宮詞  其一五','宋徽宗','宋','宋诗','song-poetry','','[]','雲巖小石碧嶙峋，瑩徹仍移玉座親。',32,'全唐诗/poet.song.86000.json','["雲巖小石碧嶙峋，瑩徹仍移玉座親。", "千仞喬崧雖突秀，未如纖巧具天真。"]'),
('0857553c-678e-418b-8c6b-4a4bb059731e','宮詞  其一六','宋徽宗','宋','宋诗','song-poetry','','[]','梨花如雪照庭隅，魄月淪精上海初。',32,'全唐诗/poet.song.86000.json','["梨花如雪照庭隅，魄月淪精上海初。", "禁鼓方傳宮漏閉，嬪嬙相拉夜看書。"]'),
('8308f969-2cd9-46b6-935b-53ae39050942','宮詞  其一七','宋徽宗','宋','宋诗','song-poetry','','[]','翠芳庭宇疊山圍，路轉龍盤燦陸離。',32,'全唐诗/poet.song.86000.json','["翠芳庭宇疊山圍，路轉龍盤燦陸離。", "響石因風飄冷韻，小碑刊勒祖宗詩。"]'),
('2bf63b9e-71d9-40fd-8562-66a7cf507fde','宮詞  其一八','宋徽宗','宋','宋诗','song-poetry','','[]','承平皇族益繁昌，雁序天倫令德彰。',32,'全唐诗/poet.song.86000.json','["承平皇族益繁昌，雁序天倫令德彰。", "此意綿長敦友愛，時時别殿宴親王。"]'),
('76c8e2d5-53c1-4db5-8d04-0d609111b519','宮詞  其一九','宋徽宗','宋','宋诗','song-poetry','','[]','銷金花朵遍輕羅，剪作春衣錫賜多。',32,'全唐诗/poet.song.86000.json','["銷金花朵遍輕羅，剪作春衣錫賜多。", "鬬薄只貪腰細柳，夜闌無奈峭寒何。"]'),
('35ec87a7-f47d-467a-b505-e5c69acb0101','宮詞  其二○','宋徽宗','宋','宋诗','song-poetry','','[]','求賢取士屬煕辰，朝野喧傳詔墨新。',32,'全唐诗/poet.song.86000.json','["求賢取士屬煕辰，朝野喧傳詔墨新。", "省試更增人百數，大庭將見出平津。"]'),
('2bf7e13d-e793-4b6d-84fc-0c202dc15b2b','宮詞  其二一','宋徽宗','宋','宋诗','song-poetry','','[]','祐神珍觀五雲開，高倚層霄疊玉臺。',32,'全唐诗/poet.song.86000.json','["祐神珍觀五雲開，高倚層霄疊玉臺。", "笑語半空知遠近，縱觀飛騎拂塵來。"]'),
('8797f2bb-cedf-4e46-ab99-2a03a58d1f1d','宮詞  其二二','宋徽宗','宋','宋诗','song-poetry','','[]','碧紗窗薄晃朝曦，睡起心情不自持。',32,'全唐诗/poet.song.86000.json','["碧紗窗薄晃朝曦，睡起心情不自持。", "糚飾尚慵臨曲檻，却敎鸚鵡念新詩。"]'),
('5652ce80-b37b-4854-96c6-1ca5ebae89ae','宮詞  其二三','宋徽宗','宋','宋诗','song-poetry','','[]','綠攪蘭芽繞徑隅，日融花氣暖縈紆。',32,'全唐诗/poet.song.86000.json','["綠攪蘭芽繞徑隅，日融花氣暖縈紆。", "鞦韆伴侶時相約，畫板繒繩翠袖扶。"]'),
('7d149e76-e2cc-47d9-abcd-4387aa691144','宮詞  其二四','宋徽宗','宋','宋诗','song-poetry','','[]','雅頌形容各訓箋，后妃基化國風先。',32,'全唐诗/poet.song.86000.json','["雅頌形容各訓箋，后妃基化國風先。", "卷分二十求深旨，親著全經正論篇。"]'),
('f3e9975a-4593-4939-b0a1-e7225023a176','宮詞  其二五','宋徽宗','宋','宋诗','song-poetry','','[]','深庭窗月透輕紗，仙侣勤工組繡華。',32,'全唐诗/poet.song.86000.json','["深庭窗月透輕紗，仙侣勤工組繡華。", "笑語竟將心事卜，只知相顧看燈花。"]'),
('7ec1b7cf-c896-4de1-9502-776e547229cc','宮詞  其二六','宋徽宗','宋','宋诗','song-poetry','','[]','崇政西清闢講筵，簪裾雜遝盡英賢。',32,'全唐诗/poet.song.86000.json','["崇政西清闢講筵，簪裾雜遝盡英賢。", "守成當謹持盈戒，紬繹鳧鷖大雅篇。"]'),
