('7a490e32-c6d4-4825-ba51-bb319f9b4f97','玉清樂  其三','宋徽宗','宋','宋诗','song-poetry','','[]','羽童呼吸辟非煙，煙氣徘徊綠室前。',32,'全唐诗/poet.song.86000.json','["羽童呼吸辟非煙，煙氣徘徊綠室前。", "造化不從身外得，自根自本即三天。"]'),
('c54917c7-cc82-46e2-a6d8-d21ccecaf151','玉清樂  其四','宋徽宗','宋','宋诗','song-poetry','','[]','帝景相將會玉洲，月真層觀紫雲浮。',32,'全唐诗/poet.song.86000.json','["帝景相將會玉洲，月真層觀紫雲浮。", "掣開三八黄金鎖，無極虛皇在上頭。"]'),
('6104b6e4-1774-48a2-a744-cf120ee94d47','玉清樂  其五','宋徽宗','宋','宋诗','song-poetry','','[]','白玉飛符下紫庭，華旛三舉召群靈。',32,'全唐诗/poet.song.86000.json','["白玉飛符下紫庭，華旛三舉召群靈。", "攀條咀嚼空青蕊，五體金光射日星。"]'),
('7944e178-f1c1-4a89-b495-c61d5f6fd45f','玉清樂  其六','宋徽宗','宋','宋诗','song-poetry','','[]','遠昌臺下海揚波，得道高真始得過。',32,'全唐诗/poet.song.86000.json','["遠昌臺下海揚波，得道高真始得過。", "下格小仙追莫及，邕邕遙聽八鸞和。"]'),
('9b8b4eb5-bcc4-4150-b3f7-758435db1606','玉清樂  其七','宋徽宗','宋','宋诗','song-poetry','','[]','五色雲營靉靉屯，三三洞戶敞瓊門。',32,'全唐诗/poet.song.86000.json','["五色雲營靉靉屯，三三洞戶敞瓊門。", "何方道士通朱表，玉女飛函達上尊。"]'),
('c363c13f-ffcc-49c5-922e-2b16c371ad3c','玉清樂  其八','宋徽宗','宋','宋诗','song-poetry','','[]','上景三元妙色精，絳宮久已列仙名。',32,'全唐诗/poet.song.86000.json','["上景三元妙色精，絳宮久已列仙名。", "更從大混存雌一，縹緲雲車駕羽明。"]'),
('de83cc63-adff-4cbb-b16a-820dc2aed3b1','玉清樂  其九','宋徽宗','宋','宋诗','song-poetry','','[]','真陽館裏氣徘徊，升降三宮密往來。',32,'全唐诗/poet.song.86000.json','["真陽館裏氣徘徊，升降三宮密往來。", "生死不忓浮世事，相將五老上金臺。"]'),
('d825cab9-2bf9-46d1-acc4-a5120d9e3d5b','玉清樂  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','三華太素自然生，空裏芙蓉灼灼明。',32,'全唐诗/poet.song.86000.json','["三華太素自然生，空裏芙蓉灼灼明。", "絳室金房虛寶座，大微童子下相迎。"]'),
('52268002-231e-4a68-b34f-ee3772eabc59','上清樂  其一','宋徽宗','宋','宋诗','song-poetry','','[]','紫清天上育華林，絳實朱柯竹葉深。',32,'全唐诗/poet.song.86000.json','["紫清天上育華林，絳實朱柯竹葉深。", "咀嚼繁英身不老，下觀鳥兔換光陰。"]'),
('02339d9f-17e5-43c7-9429-2d4e60c0caaa','上清樂  其二','宋徽宗','宋','宋诗','song-poetry','','[]','元君八氣號青靈，錦帔飛裙住玉城。',32,'全唐诗/poet.song.86000.json','["元君八氣號青靈，錦帔飛裙住玉城。", "把握帝符司道籍，拔除塵累濟群生。"]'),
('41c58b13-4559-4c1f-b429-e3abaddc7523','上清樂  其三','宋徽宗','宋','宋诗','song-poetry','','[]','高上皇人宴紫霄，擷芳常引八騫條。',32,'全唐诗/poet.song.86000.json','["高上皇人宴紫霄，擷芳常引八騫條。", "肌膚表裏瑠璃徹，映照三塗萬苦消。"]'),
('d8dce1b9-1804-4f25-b8be-27c5f39d8132','上清樂  其四','宋徽宗','宋','宋诗','song-poetry','','[]','九日宮中四老真，廣霞山上宴仙賓。',32,'全唐诗/poet.song.86000.json','["九日宮中四老真，廣霞山上宴仙賓。", "鳴鐘鼓瑟行靈醑，碧落融融別有春。"]'),
('c04ccebf-f133-41e5-87dd-7225264876f0','上清樂  其五','宋徽宗','宋','宋诗','song-poetry','','[]','浮絕山連白玉京，金華樓共日華明。',32,'全唐诗/poet.song.86000.json','["浮絕山連白玉京，金華樓共日華明。", "五真結就圓珠氣，骨似丹瓊貌似嬰。"]'),
('9386aabe-317c-4eff-b2b6-adf3aa1dea88','上清樂  其六','宋徽宗','宋','宋诗','song-poetry','','[]','秀華峰下五靈都，元景神君握化樞。',32,'全唐诗/poet.song.86000.json','["秀華峰下五靈都，元景神君握化樞。", "真火有功能造物，銷鎔五毒出陰途。"]'),
('12f3786c-113a-4f91-a96e-145fcf1ce238','上清樂  其七','宋徽宗','宋','宋诗','song-poetry','','[]','赫赫曈曈日九輪，六淵宮殿紫元君。',32,'全唐诗/poet.song.86000.json','["赫赫曈曈日九輪，六淵宮殿紫元君。", "霞冠錦帔端居暇，披拂祥煙著赤文。"]'),
('9cd73f65-6e73-4b9c-9d09-0c5ffbd4c64a','上清樂  其八','宋徽宗','宋','宋诗','song-poetry','','[]','佳氣青葱覆紫空，青精羽駕命元童。',32,'全唐诗/poet.song.86000.json','["佳氣青葱覆紫空，青精羽駕命元童。", "逆風浩蕩三千里，七返香煙處處通。"]'),
('fea9d2e5-5797-4244-9f06-d4b96dcacabe','上清樂  其九','宋徽宗','宋','宋诗','song-poetry','','[]','流汩池中大寶蓮，開花十丈映池泉。',32,'全唐诗/poet.song.86000.json','["流汩池中大寶蓮，開花十丈映池泉。", "嗅香飲水無饑渴，綽約金華葉上仙。"]'),
('04f62785-fc7f-4184-82f0-c1b13b242f38','上清樂  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','萬仞霞山峙玉虛，四司冠劍護靈都。',32,'全唐诗/poet.song.86000.json','["萬仞霞山峙玉虛，四司冠劍護靈都。", "眾真稽首持天禁，腰佩仙皇逸錄符。"]'),
('17fccfb5-5313-44b4-b72b-2609775e70a5','太清樂  其一','宋徽宗','宋','宋诗','song-poetry','','[]','太一元君掌列仙，彤暉絳彩射芝田。',32,'全唐诗/poet.song.86000.json','["太一元君掌列仙，彤暉絳彩射芝田。", "功圓會遇刊名籍，可但洪崖笑拍肩。"]'),
('120c01a7-de4f-43a2-862f-fd4dd2dfc707','太清樂  其二','宋徽宗','宋','宋诗','song-poetry','','[]','五節清香半夜焚，天人玉女盡遙聞。',32,'全唐诗/poet.song.86000.json','["五節清香半夜焚，天人玉女盡遙聞。", "味同氣合遙相應，絳節霓旌下五雲。"]'),
('b945e4ee-1baf-4e48-97ac-0c4c202e187d','太清樂  其三','宋徽宗','宋','宋诗','song-poetry','','[]','太極元君翠翮車，萬魔奔走聽神符。',32,'全唐诗/poet.song.86000.json','["太極元君翠翮車，萬魔奔走聽神符。", "九龍縱步齊驤首，時見空中吐火珠。"]'),
('94cfa62c-5604-4ea8-8d3e-048e5b407722','太清樂  其四','宋徽宗','宋','宋诗','song-poetry','','[]','蕊珠宮裏七言成，十二神君一一名。',32,'全唐诗/poet.song.86000.json','["蕊珠宮裏七言成，十二神君一一名。", "雲擁蒼虬歸火府，風隨素虎出滄瀛。"]'),
('0107b078-4203-4393-a40b-937b32b06c97','太清樂  其五','宋徽宗','宋','宋诗','song-poetry','','[]','金闕明光後聖君，流津煥彩結丹雲。',32,'全唐诗/poet.song.86000.json','["金闕明光後聖君，流津煥彩結丹雲。", "不因太上相傳授，安得人間有玉文。"]'),
('f44a6b64-b605-4b07-a00e-acda59cbcb6b','太清樂  其六','宋徽宗','宋','宋诗','song-poetry','','[]','元景巖巒聳太空，彭彭仙室在霞中。',32,'全唐诗/poet.song.86000.json','["元景巖巒聳太空，彭彭仙室在霞中。", "九靈變化俄離合，羽駕飄颻不可窮。"]'),
('1574fd00-88ea-4f9b-bd2f-4436fa1eaffa','太清樂  其七','宋徽宗','宋','宋诗','song-poetry','','[]','東井中涵皓月精，群龍奮搦運金甖。',32,'全唐诗/poet.song.86000.json','["東井中涵皓月精，群龍奮搦運金甖。", "仙人灌沐知何代，唯見玻瓈透骨明。"]'),
('ef31f5b9-841b-4a87-8306-4208e2afe895','太清樂  其八','宋徽宗','宋','宋诗','song-poetry','','[]','渺渺三津繞帝川，川連紅霧霧連天。',32,'全唐诗/poet.song.86000.json','["渺渺三津繞帝川，川連紅霧霧連天。", "玉靈仙母時遊息，侍衛森羅日月軿。"]'),
('23e4aac7-858d-4073-8d29-91177c4c0498','太清樂  其九','宋徽宗','宋','宋诗','song-poetry','','[]','九靈玉館接崑崙，山融流剛不可親。',32,'全唐诗/poet.song.86000.json','["九靈玉館接崑崙，山融流剛不可親。", "囑付紫蘭令說與，紅塵何苦弊精神。"]'),
('c4b985af-ec58-4289-9be2-4ff6cb52a58c','太清樂  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','左右靈飛運甲庚，琳房八景鍊華精。',32,'全唐诗/poet.song.86000.json','["左右靈飛運甲庚，琳房八景鍊華精。", "常陽宴罷歸何處，擲火流金事尅成。"]'),
('846650d1-87be-423b-b09c-a86b62c3d0d7','步虛詞  其一','宋徽宗','宋','宋诗','song-poetry','','[]','太極分高厚，輕清上屬天。',48,'全唐诗/poet.song.86000.json','["太極分高厚，輕清上屬天。", "人能修至道，身乃作真仙。", "行溢三千數，時丁四萬年。", "丹臺開寶笈，金口爲流傳。"]'),
('c4c350a3-525c-4f3e-acce-1280a4926126','步虛詞  其二','宋徽宗','宋','宋诗','song-poetry','','[]','太梵三天主，虛皇五老尊。',48,'全唐诗/poet.song.86000.json','["太梵三天主，虛皇五老尊。", "尚難窺徼妙，豈復入名言。", "寶座臨金殿，霞冠照玉軒。", "萬真朝帝所，飛舄躡雲根。"]'),
('27072252-bf7d-473b-8192-f2ec8ebd1586','步虛詞  其三','宋徽宗','宋','宋诗','song-poetry','','[]','濛濛如細霧，冉冉曳銖衣。',48,'全唐诗/poet.song.86000.json','["濛濛如細霧，冉冉曳銖衣。", "妙逐祥煙上，輕隨綵鳳飛。", "幾陪瑤室宴，忽指洞天歸。", "竚立扶桑岸，高奔日帝輝。"]'),
('33a22df5-63b6-4312-b677-ca7f04de8b0d','步虛詞  其四','宋徽宗','宋','宋诗','song-poetry','','[]','旋步雲綱上，天風颯爾吹。',48,'全唐诗/poet.song.86000.json','["旋步雲綱上，天風颯爾吹。", "飄裾凌斗柄，秉笏揖參箕。", "獅子銜丹綬，騏驎導翠輜。", "飛行周八極，幾見發椿枝。"]'),
('8c7ac1af-1db6-4499-8fa5-6d0973e7a535','步虛詞  其五','宋徽宗','宋','宋诗','song-poetry','','[]','綠鬢頹雲髻，青霞絡羽衣。',48,'全唐诗/poet.song.86000.json','["綠鬢頹雲髻，青霞絡羽衣。", "晨趨陽德館，夜造月華扉。", "摶弄周天火，韜潛起陸機。", "玉房留不住，卻向九霄飛。"]'),
('a79a9475-a45e-47cf-a115-6b4af03c385d','步虛詞  其六','宋徽宗','宋','宋诗','song-poetry','','[]','昔在延恩殿，中宵降九皇。',48,'全唐诗/poet.song.86000.json','["昔在延恩殿，中宵降九皇。", "六真分左右，黄霧遶軒廊。", "廣內尊神御，仙兵護道場。", "孝孫今繼志，咫尺對靈光。"]'),
('a8efc9e5-395e-4d21-9734-3073f7d1ab4a','步虛詞  其七','宋徽宗','宋','宋诗','song-poetry','','[]','寶籙修真範，丹誠奏上蒼。',48,'全唐诗/poet.song.86000.json','["寶籙修真範，丹誠奏上蒼。", "冰淵臨兆庶，宵旰致平康。", "萬物消疵癘，三辰效吉祥。", "步虛聲已徹，更詠洞玄章。"]'),
('31c1eb82-04df-4394-a44d-ab79cf802032','步虛詞  其八','宋徽宗','宋','宋诗','song-poetry','','[]','宛宛神洲地，巍巍眾妙壇。',48,'全唐诗/poet.song.86000.json','["宛宛神洲地，巍巍眾妙壇。", "鶴袍來羽客，鳬舄下仙官。", "玉斝斟玄醴，瑯函啟大丹。", "至誠何以祝，四海永澄瀾。"]'),
('d1cc94ed-b809-42d9-bf33-d2bf1f338106','步虛詞  其九','宋徽宗','宋','宋诗','song-poetry','','[]','水噀魔宮懾，燈開夜府明。',48,'全唐诗/poet.song.86000.json','["水噀魔宮懾，燈開夜府明。", "九天風靜默，四極氣澄清。", "嘯咏朱陵曲，翱翔白玉京。", "至誠何以祝，國祚永安榮。"]'),
('c8b6ddf5-2817-4b8d-89a8-247508fd536e','步虛詞  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','華夏吟哦遠，人聲自抑揚。',48,'全唐诗/poet.song.86000.json','["華夏吟哦遠，人聲自抑揚。", "沖虛歸道德，曲折合宮商。", "殿閣沉檀散，樓臺月露涼。", "至誠何以祝，多稼永豐穰。"]'),
('47a27914-f045-4d71-a0a9-55c2b2f06bf3','散花詞  其一','宋徽宗','宋','宋诗','song-poetry','','[]','絳節徘徊引，天花散漫飛。',24,'全唐诗/poet.song.86000.json','["絳節徘徊引，天花散漫飛。", "高真無染著，片片不沾衣。"]'),
('15a1d89d-0b7b-490e-9e3a-bd81b9930f27','散花詞  其二','宋徽宗','宋','宋诗','song-poetry','','[]','八陛旋瑤級，千花颺錦英。',24,'全唐诗/poet.song.86000.json','["八陛旋瑤級，千花颺錦英。", "綠渟並紫奈，煥麗不知名。"]'),
('b7ecc2d2-05bb-4cc8-a51c-97b6bab6ef45','散花詞  其三','宋徽宗','宋','宋诗','song-poetry','','[]','淺淺黄金萼，勻勻白玉英。',24,'全唐诗/poet.song.86000.json','["淺淺黄金萼，勻勻白玉英。", "天風隨御駕，吹滿九重城。"]'),
('edf2c14a-347b-4b90-b057-04f68a2b5487','散花詞  其四','宋徽宗','宋','宋诗','song-poetry','','[]','綽約縈空際，繽紛落座隅。',24,'全唐诗/poet.song.86000.json','["綽約縈空際，繽紛落座隅。", "韶華長不老，何處覓仙都。"]'),
('36fb7ecc-61fa-4465-aa1a-de9a8499b903','散花詞  其五','宋徽宗','宋','宋诗','song-poetry','','[]','凈侶吟仙曲，人人讚善哉。',48,'全唐诗/poet.song.86000.json','["凈侶吟仙曲，人人讚善哉。", "萬花興供養，飛舞自天來。", "寶葉開琪圃，珍柯在紫微。", "不教蝴蝶採，長共綵鸞飛。"]'),
('9a467439-b4fa-4123-a83e-371c0bfc26bc','散花詞  其六','宋徽宗','宋','宋诗','song-poetry','','[]','聖境三千歲，仙花始一開。',24,'全唐诗/poet.song.86000.json','["聖境三千歲，仙花始一開。", "如何金籙會，併奉列真來。"]'),
('d474d077-fb8e-4898-b78d-7af3ef7ebefd','散花詞  其七','宋徽宗','宋','宋诗','song-poetry','','[]','几席延飈馭，香燈建寶壇。',24,'全唐诗/poet.song.86000.json','["几席延飈馭，香燈建寶壇。", "丹心無可獻，碎錦灑雲端。"]'),
('51bbe895-f972-434f-a76e-eb1b13272fa8','散花詞  其八','宋徽宗','宋','宋诗','song-poetry','','[]','碧綠相差次，紅黄迭淺深。',24,'全唐诗/poet.song.86000.json','["碧綠相差次，紅黄迭淺深。", "化工應自失，雕斵本何心。"]'),
('aba1c524-2b14-4f14-993b-6ce3f01613c5','散花詞  其九','宋徽宗','宋','宋诗','song-poetry','','[]','洞案爐煙起，無爲道德香。',24,'全唐诗/poet.song.86000.json','["洞案爐煙起，無爲道德香。", "同根無異氣，噴鼻更芬芳。"]'),
('ad6cdafd-ff5a-4227-afae-32b2e36ddd77','白鶴詞  其一','宋徽宗','宋','宋诗','song-poetry','','[]','胎化靈禽唳九天，雪毛丹頂兩相鮮。',32,'全唐诗/poet.song.86000.json','["胎化靈禽唳九天，雪毛丹頂兩相鮮。", "世人莫認歸華表，來瑞昇平億萬年。"]'),
('be84f309-39b0-4d56-af48-ff382ad6ce53','白鶴詞  其二','宋徽宗','宋','宋诗','song-poetry','','[]','瑤臺風靜夜初分，仰喙驚鳴露氣新。',32,'全唐诗/poet.song.86000.json','["瑤臺風靜夜初分，仰喙驚鳴露氣新。", "太液徘徊歸未得，曾於往劫作麒麟。"]'),
('5c6f414f-3299-488c-9daa-e540d78e7181','白鶴詞  其三','宋徽宗','宋','宋诗','song-poetry','','[]','靈鶴翩翩下太清，玉樓金殿曉風輕。',32,'全唐诗/poet.song.86000.json','["靈鶴翩翩下太清，玉樓金殿曉風輕。", "昂昂不與雞爲侶，時作沖天物外聲。"]'),
('d39d3823-dcc4-415b-a494-50041daf9c1a','白鶴詞  其四','宋徽宗','宋','宋诗','song-poetry','','[]','三山碧海路非遙，來瑞清都下紫霄。',32,'全唐诗/poet.song.86000.json','["三山碧海路非遙，來瑞清都下紫霄。", "霜雪羽毛冰玉性，瑤池深處啄靈苗。"]'),
('2bac1c89-b235-4d0d-a9df-0304b4679828','白鶴詞  其五','宋徽宗','宋','宋诗','song-poetry','','[]','金火純精見羽儀，長隨王母宴瑤池。',32,'全唐诗/poet.song.86000.json','["金火純精見羽儀，長隨王母宴瑤池。", "玉壇夜醮神仙降，飛過緱山人不知。"]'),
('bb694296-7ab9-43b8-84da-9dd1267971a0','白鶴詞  其六','宋徽宗','宋','宋诗','song-poetry','','[]','五雲宮殿步虛長，斗轉旋霄夜未央。',32,'全唐诗/poet.song.86000.json','["五雲宮殿步虛長，斗轉旋霄夜未央。", "白鶴飛來通吉信，清音齊逐返魂香。"]'),
('4c8fe6be-9e17-45ca-9c48-9b910d1d94f0','白鶴詞  其七','宋徽宗','宋','宋诗','song-poetry','','[]','一聲嘹唳九臯禽，換骨輕清歲月深。',32,'全唐诗/poet.song.86000.json','["一聲嘹唳九臯禽，換骨輕清歲月深。", "遼海等閑人不識，大羅天上有知音。"]'),
('9c17471c-dd99-4bf6-b9e3-5c5f0884db8b','白鶴詞  其八','宋徽宗','宋','宋诗','song-poetry','','[]','白毛鮮潔映霜華，丹頂分明奪絳紗。',32,'全唐诗/poet.song.86000.json','["白毛鮮潔映霜華，丹頂分明奪絳紗。", "千六百年神氣就，飛鳴長伴玉仙家。"]'),
('bd0b6657-bacb-475e-b9c7-86d55b70d633','白鶴詞  其九','宋徽宗','宋','宋诗','song-poetry','','[]','蓬萊會散列仙歸，羽駕飄然白鶴飛。',32,'全唐诗/poet.song.86000.json','["蓬萊會散列仙歸，羽駕飄然白鶴飛。", "明代爲祥人慣見，何須樂府詠金衣。"]'),
('6bf30efa-aecd-4db1-baf1-3cba54de052c','白鶴詞  其一○','宋徽宗','宋','宋诗','song-poetry','','[]','玉宇沉沉瑞霧開，香風未斷鶴徘徊。',32,'全唐诗/poet.song.86000.json','["玉宇沉沉瑞霧開，香風未斷鶴徘徊。", "奇姿會與青田別，定是仙人次第來。"]'),
('6e560af3-6bb4-423a-9f97-74c9a5c309fd','長吟玉音金闕步虛','宋徽宗','宋','宋诗','song-poetry','','[]','始青黎元蓋，金香結朱煙。',60,'全唐诗/poet.song.86000.json','["始青黎元蓋，金香結朱煙。", "飛晨總翹轡，稽首玉帝前。", "帝心浩以舒，錫吾太靈篇。", "是謂不滅道，萬天秉吾權。", "吾行空洞中，下仙昧其淵。"]'),
('d4fc1395-5f00-47ae-9148-83398497eddb','步虛詞二首  其一','宋徽宗','宋','宋诗','song-poetry','','[]','一氣化之元，邈在兩儀先。',60,'全唐诗/poet.song.86000.json','["一氣化之元，邈在兩儀先。", "寶埒馳金馬，真香噴玉蓮。", "飛空按龍轡，梵響導芝軿。", "綿永長春劫，翱翔無色天。", "初真難曉諭，以此戒中仙。"]'),
('e8382f59-989c-4934-ade7-215fb3fd9d7d','步虛詞二首  其二','宋徽宗','宋','宋诗','song-poetry','','[]','高真明道德，垂世五千言。',60,'全唐诗/poet.song.86000.json','["高真明道德，垂世五千言。", "解釋慚涼薄，殫誠測妙元。", "霓旌嚴教典，羽唱徹雲軿。", "瑞鶴儀空際，祥風拂署煩。", "穹窿茲響應，寶祚億斯年。"]'),
('91e996e9-4e2c-4aab-a47e-68c32fa856a1','題芙蓉錦雞圖','宋徽宗','宋','宋诗','song-poetry','','[]','秋勁拒霜盛，峨冠錦羽雞。',24,'全唐诗/poet.song.86000.json','["秋勁拒霜盛，峨冠錦羽雞。", "已知全五德，安逸勝鳬鷖。"]'),
('6cf28efd-75de-4362-89fa-5608e3bef8eb','題祥龍石圖','宋徽宗','宋','宋诗','song-poetry','','[]','彼美蜿蜒勢若龍，挺然爲瑞獨稱雄。',64,'全唐诗/poet.song.86000.json','["彼美蜿蜒勢若龍，挺然爲瑞獨稱雄。", "雲凝好色來相借，水潤清輝更不同。", "常带暝煙疑振鬣，每乘宵雨恐凌空。", "故憑彩筆親模寫，融結功深未易窮。"]'),
('3860d558-eec7-40ac-a14c-31964029f8c8','題瑞鶴圖','宋徽宗','宋','宋诗','song-poetry','','[]','清曉觚稜拂彩霓，仙禽告瑞忽來儀。',64,'全唐诗/poet.song.86000.json','["清曉觚稜拂彩霓，仙禽告瑞忽來儀。", "飄飄元是三山侶，兩兩還呈千歲姿。", "似擬碧鸞棲寶閣，豈同赤雁集天池。", "徘徊嘹唳當丹闕，故使憧憧庶俗知。"]'),
('68730e73-ac40-4054-936e-3dc37fe63157','詩一首','宋徽宗','宋','宋诗','song-poetry','','[]','穠芳依翠萼，煥爛一庭中。',48,'全唐诗/poet.song.86000.json','["穠芳依翠萼，煥爛一庭中。", "零露霑如醉，殘霞照似融。", "丹青難下筆，造化獨留功。", "舞蝶迷香徑，翩翩逐晚風。"]'),
('84470c89-cc18-45f3-8e0d-f9aacf78a3df','打毬詩','宋徽宗','宋','宋诗','song-poetry','','[]','錦袍駿馬曉棚分，一點星馳百騎奔。',32,'全唐诗/poet.song.86000.json','["錦袍駿馬曉棚分，一點星馳百騎奔。", "奪得頭籌須正過，無令綽撥入邪門。"]'),
('57430234-3cc4-4c32-878c-cf0d4c6258c3','題雙檜','宋徽宗','宋','宋诗','song-poetry','','[]','拔翠琪樹林，雙檜植靈囿。',48,'全唐诗/poet.song.86000.json','["拔翠琪樹林，雙檜植靈囿。", "上稍蟠木枝，下拂龍髯茂。", "撐拏天半分，連卷虹南負。", "爲棟復爲梁，夾輔我皇構。"]'),
('6d0fe800-f22d-4af4-8848-f8db8f27c902','題燕山僧寺壁','宋徽宗','宋','宋诗','song-poetry','','[]','九葉鴻基一旦休，猖狂不聽直臣謀。',32,'全唐诗/poet.song.86000.json','["九葉鴻基一旦休，猖狂不聽直臣謀。", "甘心萬里爲降虜，故國悲涼玉殿秋。"]'),
('ba495369-ccfa-4573-9efb-b4b3715de968','泰陵挽詞  其一','宋徽宗','宋','宋诗','song-poetry','','[]','武帳初籌夜，雲駢忽帝鄉。',48,'全唐诗/poet.song.86000.json','["武帳初籌夜，雲駢忽帝鄉。", "百神陪禹葬，三載服堯喪。", "北極聯龍袞，西風拆雁行。", "空餘千古事，纘述愧重光。"]'),
('2cbe9f37-68b2-4e3c-bd0b-64eeed02c458','泰陵挽詞  其二','宋徽宗','宋','宋诗','song-poetry','','[]','姑射仙期早，華胥夢已陳。',50,'全唐诗/poet.song.86000.json','["姑射仙期早，華胥夢已陳。", "朝廷繫聖母，基業付沖人。", "日轉銅壺影，天移玉座春。", "九病夫用笳鼓發，悲動屬車塵。"]'),
('3c9c6cf6-c239-45db-b85b-247ef174af72','泰陵挽詞  其三','宋徽宗','宋','宋诗','song-poetry','','[]','睿哲天攸縱，神機智獨謀。',48,'全唐诗/poet.song.86000.json','["睿哲天攸縱，神機智獨謀。", "塵流藏寶閣，鎖鑰受降樓。", "風急鴒原晚，霜寒雁宿秋。", "遺衣今在寢，猶想未明求。"]'),
('3dc19fb9-4758-4557-9fa6-e50d21eaa5eb','泰陵挽詞  其四','宋徽宗','宋','宋诗','song-poetry','','[]','再御中天坐，猶思玉色溫。',48,'全唐诗/poet.song.86000.json','["再御中天坐，猶思玉色溫。", "瑤階花自落，寶扇影空存。", "重感天倫戚，欽承世及恩。", "欲諧追述志，永紹裕陵尊。"]'),
('4d17e992-542e-4d68-9e2c-1afb9083435a','泰陵挽詞  其五','宋徽宗','宋','宋诗','song-poetry','','[]','憶開王邸日，曾駐六龍飛。',48,'全唐诗/poet.song.86000.json','["憶開王邸日，曾駐六龍飛。", "玉宇春初永，金盤露未晞。", "荆根方並秀，棣萼更交輝。", "今日承基緒，追懷往事非。"]'),
('f6a4fd10-ebed-4045-9421-e0a4239b3fab','甘露','宋徽宗','宋','宋诗','song-poetry','','[]','政成天地不相違，瑞應中臺贊萬幾。',64,'全唐诗/poet.song.86000.json','["政成天地不相違，瑞應中臺贊萬幾。", "夜浥垂珠濡綠葉，朝凝潤玉弄清輝。", "仙盆雲表秋難比，豐草宵零日未晞。", "本自君臣俱會合，更嘉報上美能歸。"]'),
('26447488-50fa-4e7b-8e34-e095ad32f617','賜和蔡京','宋徽宗','宋','宋诗','song-poetry','','[]','道德方今喜迭興，萬邦從化本天成。',32,'全唐诗/poet.song.86000.json','["道德方今喜迭興，萬邦從化本天成。", "定知金帝來爲主，不待春風便發生。"]'),
('4d37f8ca-3340-4506-953b-b9e3dc463c45','保和殿下荔枝成實賜王安中','宋徽宗','宋','宋诗','song-poetry','','[]','保和殿下荔枝丹，文武衣冠被百蠻。',32,'全唐诗/poet.song.86000.json','["保和殿下荔枝丹，文武衣冠被百蠻。", "思與近世同此味，紅塵飛鞚過燕山。"]'),
('5e769cef-5b52-43e5-8334-21a09b469c2d','宣和殿移植荔枝','宋徽宗','宋','宋诗','song-poetry','','[]','密移造化出閩山，禁御新栽荔子丹。',64,'全唐诗/poet.song.86000.json','["密移造化出閩山，禁御新栽荔子丹。", "山液乍凝仙掌露，絳苞初綻水精丸。", "酒酣國艷非朱粉，風泛天香轉蕙蘭。", "何必紅塵飛無騎，芬芳數本座中看。"]'),
('cd7bec3a-61d1-4f15-9733-8d6abb4a0078','己亥十一月十三日南郊祭天齋宮即事賜太師','宋徽宗','宋','宋诗','song-poetry','','[]','報本精禋自國南，先期清廟宿齋嚴。',64,'全唐诗/poet.song.86000.json','["報本精禋自國南，先期清廟宿齋嚴。", "層霄初擴同雲霽，暖吹俄回海日暹。", "十萬軍容冰作陣，九街鴛瓦玉爲簷。", "肅雍顯相同元老，行慶均釐四海霑。"]'),
('c9cc612a-e58f-4ff8-80e4-6a133e90265f','清廟齋幄常有詩賜太師已曾和進禋祀禮成以目擊之事依前韻再進今亦用元韻復賜太師非特以此相困蓋清時君臣賡載亦一時盛事耳','宋徽宗','宋','宋诗','song-poetry','','[]','靈鼓黄麾道指南，紫壇蒼璧示凝嚴。',64,'全唐诗/poet.song.86000.json','["靈鼓黄麾道指南，紫壇蒼璧示凝嚴。", "聯翩玉羽層霄下，烜赫神光愛景暹。", "爲喜鸞輿回鳳闕，故留芝蓋出虬簷。", "禮天要作斯民福，解雨今當萬物霑。"]'),
('2b3bf0d2-ec52-44b6-a995-e1c1f468ee47','太師以被賜暹字韻詩前後凡三次進和蓋欲示其韻愈嚴而愈工耳復以前韻又賜太師','宋徽宗','宋','宋诗','song-poetry','','[]','天位迎陽轉斗南，千官山立盡恭嚴。',64,'全唐诗/poet.song.86000.json','["天位迎陽轉斗南，千官山立盡恭嚴。", "共欣奠玉煙初達，爭奉回鸞日已暹。", "歸問雪中誰詠絮，冥搜花底自巡簷。", "禮成卻喜歌盈尺，端爲來麰萬宇霑。"]'),
('22b19687-aea9-48a0-b94f-291155f6d534','神霄玉清萬壽宮慶成卿以使事奉安聖像聞有二詩書幈俯同其韻復賜太師  其一','宋徽宗','宋','宋诗','song-poetry','','[]','碧落金風爽氣回，叢霄乍喜瑞霞開。',32,'全唐诗/poet.song.86000.json','["碧落金風爽氣回，叢霄乍喜瑞霞開。", "經營欲致黎元福，敢謂詩人詠子來。"]'),
('db239f77-eaaa-4cd8-a346-041d8b4c1407','神霄玉清萬壽宮慶成卿以使事奉安聖像聞有二詩書幈俯同其韻復賜太師  其二','宋徽宗','宋','宋诗','song-poetry','','[]','曈曚日馭曉光回，金碧相宜玉府開。',32,'全唐诗/poet.song.86000.json','["曈曚日馭曉光回，金碧相宜玉府開。", "步武煙霞還舊觀，百神應喜左元來。"]'),
('a7f6336d-3476-40b2-9ba2-fc733de69288','昨日召卿等自卿私第泛舟經景龍江游擷芳園靈沼聞卿有小詩今俯同其韻賜太師  其一','宋徽宗','宋','宋诗','song-poetry','','[]','景龍江靜喜安流，玉色閑看浴翅鷗。',32,'全唐诗/poet.song.86000.json','["景龍江靜喜安流，玉色閑看浴翅鷗。", "已覺西風頗無事，何妨穩泛濟川舟。"]');
